export const MAGNETISM_OS = "# MAGNETISM OS\n## \u041e\u0441\u043e\u0431\u0438\u0441\u0442\u0438\u0439 \u043c\u0435\u043d\u0442\u043e\u0440 \u0434\u043b\u044f \u0412\u0456\u0442\u0430\u043b\u0456\u044f \u2014 \u0421\u0442\u0438\u043b\u044c \u00b7 \u041f\u0440\u0438\u0441\u0443\u0442\u043d\u0456\u0441\u0442\u044c \u00b7 \u041f\u0435\u0440\u0435\u0433\u043e\u0432\u043e\u0440\u0438 \u00b7 \u0424\u043b\u0456\u0440\u0442 \u00b7 \u0421\u0435\u0440\u0446\u044f\n\n> \"\u0422\u0438 \u043d\u0435 \u0437\u0430\u0432\u043e\u0439\u043e\u0432\u0443\u0454\u0448. \u0422\u0438 \u0441\u0442\u0430\u0454\u0448 \u0442\u0438\u043c, \u043a\u043e\u0433\u043e \u043e\u0431\u0438\u0440\u0430\u044e\u0442\u044c.\"\n\n---\n\n## \ud83c\udfaf \u0424\u0406\u041b\u041e\u0421\u041e\u0424\u0406\u042f\n\n\u041c\u0430\u0433\u043d\u0435\u0442\u0438\u0437\u043c \u2014 \u0446\u0435 \u043d\u0435 \u0442\u0435\u0445\u043d\u0456\u043a\u0438. \u0426\u0435 \u0444\u043e\u0440\u043c\u0443\u043b\u0430 Olivia Fox Cabane:\n\n**\u041c\u0430\u0433\u043d\u0435\u0442\u0438\u0437\u043c = \u041f\u0440\u0438\u0441\u0443\u0442\u043d\u0456\u0441\u0442\u044c \u00d7 \u0422\u0435\u043f\u043b\u043e \u00d7 \u0421\u0438\u043b\u0430**\n\n\u0412\u0441\u0435 \u0456\u043d\u0448\u0435 \u2014 \u043e\u0434\u044f\u0433, \u043f\u043e\u0433\u043b\u044f\u0434, \u0433\u043e\u043b\u043e\u0441, \u043c\u043e\u0432\u0447\u0430\u043d\u043d\u044f, \u0434\u043e\u0442\u0438\u043a \u2014 \u0446\u0435 \u043f\u0456\u0434\u0441\u0438\u043b\u044e\u0432\u0430\u0447\u0456 \u0441\u0438\u0433\u043d\u0430\u043b\u0443.\n\n**\u041f\u043e\u043c\u0438\u043b\u043a\u0430 \u0431\u0456\u043b\u044c\u0448\u043e\u0441\u0442\u0456 \u0447\u043e\u043b\u043e\u0432\u0456\u043a\u0456\u0432:** \u0432\u043e\u043d\u0438 \u0433\u0440\u0430\u044e\u0442\u044c \u0443 \"\u0437\u0430\u0432\u043e\u044e\u0432\u0430\u043d\u043d\u044f\". \u041f\u0440\u043e\u0433\u0440\u0430\u0454 \u0442\u043e\u0439, \u0445\u0442\u043e \u0441\u0442\u0430\u0454 \u043f\u0435\u0440\u0435\u0441\u043b\u0456\u0434\u0443\u0432\u0430\u0447\u0435\u043c. \u0412\u0438\u0433\u0440\u0430\u0454 \u0442\u043e\u0439, \u0445\u0442\u043e \u0441\u0442\u0430\u0454 \u043f\u043e\u043b\u044e\u0441\u043e\u043c, \u0434\u043e \u044f\u043a\u043e\u0433\u043e \u0442\u044f\u0433\u043d\u0443\u0442\u044c\u0441\u044f.\n\n\u0426\u044f \u0441\u0438\u0441\u0442\u0435\u043c\u0430 \u043d\u0435 PUA \u0437 2005-\u0433\u043e. \u041d\u0435 Tinder-\u0445\u0430\u043a\u0438. \u0426\u0435 \u043e\u043f\u0435\u0440\u0430\u0446\u0456\u0439\u043d\u0430 \u0441\u0438\u0441\u0442\u0435\u043c\u0430 \u0437\u0440\u0456\u043b\u043e\u0433\u043e \u0447\u043e\u043b\u043e\u0432\u0456\u043a\u0430 \u0437 \u043c\u0456\u0441\u0456\u0454\u044e. \u041c\u043e\u0434\u0443\u043b\u0456 1\u20133 \u043f\u0440\u0430\u0446\u044e\u044e\u0442\u044c \u0432\u0441\u044e\u0434\u0438 \u2014 \u043a\u043b\u0443\u0431\u0438, \u0441\u043f\u043e\u043d\u0441\u043e\u0440\u0438, \u0434\u0438\u0442\u0438\u043d\u0430, \u043f\u0435\u0440\u0435\u0433\u043e\u0432\u043e\u0440\u0438. \u041c\u043e\u0434\u0443\u043b\u0456 4\u20135 \u2014 \u0434\u043b\u044f \u0440\u043e\u043c\u0430\u043d\u0442\u0438\u0447\u043d\u043e\u0433\u043e \u043a\u043e\u043d\u0442\u0435\u043a\u0441\u0442\u0443.\n\n---\n\n## \ud83e\udde0 5 \u041c\u0410\u0419\u0421\u0422\u0420\u0406\u0412. \u0427\u041e\u041c\u0423 \u0421\u0410\u041c\u0415 \u0412\u041e\u041d\u0418.\n\n**1. Robert Greene \u2014 \"The Art of Seduction\" (2001)**\n\u0421\u0442\u0440\u0430\u0442\u0435\u0433\u0456\u0447\u043d\u0430 \u0433\u043b\u0438\u0431\u0438\u043d\u0430. \u0410\u0440\u0445\u0435\u0442\u0438\u043f\u0438 \u0441\u043f\u043e\u043a\u0443\u0441\u043d\u0438\u043a\u0456\u0432. \u0420\u043e\u0437\u0443\u043c\u0456\u043d\u043d\u044f: \u0441\u0438\u043b\u0430 \u2014 \u0443 \u0441\u0442\u0432\u043e\u0440\u0435\u043d\u043d\u0456 \u0431\u0430\u0436\u0430\u043d\u043d\u044f, \u043d\u0435 \u0443 \u0439\u043e\u0433\u043e \u0437\u0430\u0434\u043e\u0432\u043e\u043b\u0435\u043d\u043d\u0456.\n\n**2. Esther Perel \u2014 \"Mating in Captivity\" (2006), \"The State of Affairs\" (2017)**\n\u041d\u0430\u0439\u043a\u0440\u0430\u0449\u0438\u0439 \u0443 \u0441\u0432\u0456\u0442\u0456 \u0435\u043a\u0441\u043f\u0435\u0440\u0442 \u043f\u043e \u0431\u0430\u0436\u0430\u043d\u043d\u044e \u0432 \u0434\u043e\u0432\u0433\u0438\u0445 \u0441\u0442\u043e\u0441\u0443\u043d\u043a\u0430\u0445. \u0420\u043e\u0437\u0440\u0438\u0432 \u043c\u0456\u0436 \u0435\u0440\u043e\u0442\u0438\u043a\u043e\u044e \u0456 \u0431\u043b\u0438\u0437\u044c\u043a\u0456\u0441\u0442\u044e. \u0427\u043e\u043c\u0443 \u0442\u0435, \u0449\u043e \u043f\u0440\u0438\u0432\u0430\u0431\u043b\u044e\u0454 \u2014 \u043d\u0435 \u0437\u0430\u0432\u0436\u0434\u0438 \u0442\u0435, \u0449\u043e \u0437\u0430\u0441\u043f\u043e\u043a\u043e\u044e\u0454.\n\n**3. Chris Voss \u2014 \"Never Split the Difference\" (2016)**\n\u041a\u043e\u043b\u0438\u0448\u043d\u0456\u0439 \u0433\u043e\u043b\u043e\u0432\u043d\u0438\u0439 \u043f\u0435\u0440\u0435\u043c\u043e\u0432\u043d\u0438\u043a \u0424\u0411\u0420 \u0437 \u0437\u0430\u0440\u0443\u0447\u043d\u0438\u043a\u0456\u0432. \u041a\u0430\u043b\u0456\u0431\u0440\u043e\u0432\u0430\u043d\u0456 \u0437\u0430\u043f\u0438\u0442\u0430\u043d\u043d\u044f, \u0442\u0430\u043a\u0442\u0438\u0447\u043d\u0430 \u0435\u043c\u043f\u0430\u0442\u0456\u044f, \u0434\u0437\u0435\u0440\u043a\u0430\u043b\u0435\u043d\u043d\u044f, \u043c\u0430\u0440\u043a\u0443\u0432\u0430\u043d\u043d\u044f. \u041d\u0430\u0439\u043f\u043e\u0442\u0443\u0436\u043d\u0456\u0448\u0430 \u0441\u0438\u0441\u0442\u0435\u043c\u0430 \u0432\u043f\u043b\u0438\u0432\u0443 \u0447\u0435\u0440\u0435\u0437 \u0441\u043b\u0443\u0445.\n\n**4. Olivia Fox Cabane \u2014 \"The Charisma Myth\" (2012)**\n\u0420\u043e\u0437\u043a\u043b\u0430\u043b\u0430 \u0445\u0430\u0440\u0438\u0437\u043c\u0443 \u043d\u0430 \u0442\u0440\u0435\u043d\u0443\u0432\u0430\u043b\u044c\u043d\u0443 \u043c\u0430\u0442\u0435\u043c\u0430\u0442\u0438\u043a\u0443: \u043f\u0440\u0438\u0441\u0443\u0442\u043d\u0456\u0441\u0442\u044c + \u0442\u0435\u043f\u043b\u043e + \u0441\u0438\u043b\u0430. \u042f\u043a \u043c'\u044f\u0437.\n\n**5. Mark Manson \u2014 \"Models\" (2011), \"The Subtle Art of Not Giving a F*ck\" (2016)**\n\u0410\u0442\u0440\u0430\u043a\u0446\u0456\u044f \u0447\u0435\u0440\u0435\u0437 \u0447\u0435\u0441\u043d\u0456\u0441\u0442\u044c, \u043d\u0435 \u0447\u0435\u0440\u0435\u0437 \u0456\u0433\u0440\u0438. \u0421\u0430\u043c\u043e\u043f\u043e\u0432\u0430\u0433\u0430 \u044f\u043a \u043c\u0430\u0433\u043d\u0435\u0442\u0438\u0442. \u0427\u043e\u043c\u0443 \u043f\u0435\u0440\u0435\u0441\u043b\u0456\u0434\u0443\u0432\u0430\u043d\u043d\u044f \u0437\u043c\u0435\u043d\u0448\u0443\u0454 \u0446\u0456\u043d\u043d\u0456\u0441\u0442\u044c, \u0430 \u0441\u043f\u043e\u043a\u0456\u0439\u043d\u0430 \u043f\u0440\u0438\u0441\u0443\u0442\u043d\u0456\u0441\u0442\u044c \u2014 \u043f\u0456\u0434\u0432\u0438\u0449\u0443\u0454.\n\n---\n\n## \ud83d\udc54 \u041c\u041e\u0414\u0423\u041b\u042c 1 \u2014 \u0421\u0422\u0418\u041b\u042c \u041e\u0414\u042f\u0413\u0423\n\n**\u041f\u0440\u0438\u043d\u0446\u0438\u043f:** \u043e\u0434\u044f\u0433 \u2014 \u0446\u0435 \u0442\u0432\u043e\u044f \u043e\u0431\u043a\u043b\u0430\u0434\u0438\u043d\u043a\u0430. \u041f\u0435\u0440\u0448\u0456 7 \u0441\u0435\u043a\u0443\u043d\u0434 \u0432\u0438\u0440\u0456\u0448\u0435\u043d\u043e \u043d\u0435\u0432\u0435\u0440\u0431\u0430\u043b\u044c\u043d\u043e (Cabane).\n\n**6 \u043f\u0440\u0430\u0432\u0438\u043b:**\n\n1. **Fit > \u0431\u0440\u0435\u043d\u0434 > \u0446\u0456\u043d\u0430.** \u041a\u043e\u0441\u0442\u044e\u043c \u0437\u0430 300 \u0444\u0443\u043d\u0442\u0456\u0432, \u043f\u0456\u0434\u0448\u0438\u0442\u0438\u0439 \u043f\u0456\u0434 \u0442\u0435\u0431\u0435, \u0432\u0438\u0433\u0440\u0430\u0454 \u0432 Brioni \u0431\u0435\u0437 \u043f\u0456\u0434\u0433\u043e\u043d\u043a\u0438.\n2. **\u0421\u0438\u0433\u043d\u0430\u0442\u0443\u0440\u0430.** \u041e\u0434\u0438\u043d \u0435\u043b\u0435\u043c\u0435\u043d\u0442, \u044f\u043a\u0438\u0439 \u0437\u0430\u0432\u0436\u0434\u0438 \u0442\u0432\u0456\u0439. \u0414\u0436\u043e\u0431\u0441 \u2014 \u0432\u043e\u0434\u043e\u043b\u0430\u0437\u043a\u0430. Tom Ford \u2014 \u0434\u0432\u0456\u0439\u043a\u0430-\u043a\u043e\u0441\u0442\u044e\u043c. \u0417\u043d\u0430\u0439\u0434\u0438 \u0441\u0432\u0456\u0439.\n3. **\u0421\u0438\u043b\u0443\u0435\u0442.** \u041f\u043b\u0435\u0447\u0456, \u0442\u0430\u043b\u0456\u044f, \u043a\u0456\u0441\u0442\u043e\u0447\u043a\u0438 \u0432\u0438\u0434\u043d\u043e. \u041a\u043b\u0430\u0441\u0438\u0447\u043d\u0456 \u043f\u0440\u043e\u043f\u043e\u0440\u0446\u0456\u0457 \u2014 \u0446\u0435 \u0441\u0438\u043b\u0430.\n4. **\u041f\u0430\u043b\u0456\u0442\u0440\u0430 \u043e\u0431\u043c\u0435\u0436\u0435\u043d\u0430.** 3\u20134 \u0431\u0430\u0437\u043e\u0432\u0438\u0445 \u043a\u043e\u043b\u044c\u043e\u0440\u0438 (\u0442\u0435\u043c\u043d\u043e-\u0441\u0438\u043d\u0456\u0439, \u0433\u0440\u0430\u0444\u0456\u0442, \u043a\u0440\u0435\u043c\u043e\u0432\u0438\u0439, \u0431\u043e\u0440\u0434\u043e/\u043e\u043b\u0438\u0432\u043a\u0430). \u0412\u0441\u0435 \u043c\u0456\u043a\u0441\u0443\u0454\u0442\u044c\u0441\u044f.\n5. **Premium discreet \u0434\u0435\u0442\u0430\u043b\u0456.** \u0413\u043e\u0434\u0438\u043d\u043d\u0438\u043a, \u0432\u0437\u0443\u0442\u0442\u044f, \u043f\u0430\u0440\u0444\u0443\u043c, \u0448\u043a\u0456\u0440\u0430. \u041d\u0435 \u043b\u043e\u0433\u043e \u2014 \u044f\u043a\u0456\u0441\u0442\u044c.\n6. **\u041f\u0430\u0440\u0444\u0443\u043c \u2014 \u0442\u0432\u0456\u0439 \u043f\u0456\u0434\u043f\u0438\u0441.** \u041e\u0434\u0438\u043d \u0434\u043b\u044f \u0434\u043d\u044f (\u0441\u0432\u0456\u0436\u0438\u0439), \u043e\u0434\u0438\u043d \u0434\u043b\u044f \u0432\u0435\u0447\u043e\u0440\u0430 (\u0434\u0435\u0440\u0435\u0432\u043d\u0438\u0439/\u0448\u043a\u0456\u0440\u044f\u043d\u0438\u0439). \u0423\u043d\u0456\u043a\u0430\u043b\u044c\u043d\u0438\u0439, \u043d\u0435 \u043c\u0430\u0441\u043e\u0432\u0438\u0439.\n\n**\u0414\u043b\u044f \u0442\u0435\u0431\u0435 \u043f\u0435\u0440\u0441\u043e\u043d\u0430\u043b\u044c\u043d\u043e (Talent Mates, Apple-style):**\n- \u0422\u0435\u043c\u043d\u043e-\u0441\u0438\u043d\u0456\u0439 \u043a\u043e\u0441\u0442\u044e\u043c \u0431\u0435\u0437 \u043a\u0440\u0430\u0432\u0430\u0442\u043a\u0438 + \u0431\u0456\u043b\u0456 \u043f\u0440\u0435\u043c\u02bc\u044e\u043c-\u0441\u043d\u0456\u043a\u0435\u0440\u0441\u0438 \u2192 founder-\u0443\u043d\u0456\u0444\u043e\u0440\u043c\u0430\n- \u0413\u0440\u0430\u0444\u0456\u0442\u043d\u0435 \u043f\u043e\u043b\u043e + \u0442\u0435\u043c\u043d\u0456 \u0434\u0436\u0438\u043d\u0441\u0438 + \u0434\u0435\u0440\u0431\u0456 \u2192 \u0434\u0456\u043b\u043e\u0432\u0430 \u0437\u0443\u0441\u0442\u0440\u0456\u0447 \u0443 \u041b\u043e\u043d\u0434\u043e\u043d\u0456\n- \u041a\u0430\u0448\u0435\u043c\u0456\u0440-\u0441\u0432\u0435\u0442\u0440 + chinos + \u043b\u043e\u0444\u0435\u0440\u0438 \u2192 \u043c\u0435\u0446\u0435\u043d\u0430\u0442-\u0432\u0435\u0447\u0456\u0440, gala\n- \u0411\u043e\u043c\u0431\u0435\u0440 + selvedge denim + Common Projects \u2192 \"off-duty founder\"\n\n---\n\n## \ud83e\uddd8 \u041c\u041e\u0414\u0423\u041b\u042c 2 \u2014 \u0421\u0422\u0418\u041b\u042c \u041f\u041e\u0412\u0415\u0414\u0406\u041d\u041a\u0418 (\u041f\u0420\u0418\u0421\u0423\u0422\u041d\u0406\u0421\u0422\u042c)\n\n**\u0422\u0440\u0438\u0430\u0434\u0430 Cabane:**\n\n- **\u041f\u0440\u0438\u0441\u0443\u0442\u043d\u0456\u0441\u0442\u044c:** \u0442\u0438 \u043f\u043e\u0432\u043d\u0456\u0441\u0442\u044e \u0442\u0443\u0442. \u041d\u0435 \u0434\u0438\u0432\u0438\u0448\u0441\u044f \u0432 \u0442\u0435\u043b\u0435\u0444\u043e\u043d. \u041d\u0435 \u043f\u043b\u0430\u043d\u0443\u0454\u0448 \u043d\u0430\u0441\u0442\u0443\u043f\u043d\u0443 \u0444\u0440\u0430\u0437\u0443. \u0421\u043b\u0443\u0445\u0430\u0454\u0448.\n- **\u0422\u0435\u043f\u043b\u043e:** \u0442\u0438 \u0440\u0430\u0434\u0438\u0439 \u0431\u0430\u0447\u0438\u0442\u0438 \u0446\u044e \u043b\u044e\u0434\u0438\u043d\u0443. \u041e\u0447\u0456 \u043c'\u044f\u043a\u0456. \u0411\u0435\u0437 \u043e\u0446\u0456\u043d\u043a\u0438.\n- **\u0421\u0438\u043b\u0430:** \u0442\u0438 \u043d\u0435 \u0437\u0430\u043b\u0435\u0436\u0438\u0448 \u0432\u0456\u0434 \u0440\u0435\u0430\u043a\u0446\u0456\u0457. \u0421\u043f\u043e\u043a\u0456\u0439 \u0432\u0456\u0434 \u0432\u043d\u0443\u0442\u0440\u0456\u0448\u043d\u044c\u043e\u0457 \u043e\u043f\u043e\u0440\u0438 (\u043c\u0456\u0441\u0456\u044f, \u0431\u0456\u0437\u043d\u0435\u0441, \u0442\u0456\u043b\u043e).\n\n**\u0422\u0440\u0435\u043d\u0443\u0432\u0430\u043d\u043d\u044f (\u0449\u043e\u0434\u043d\u044f):**\n\n1. **\u0423\u043f\u043e\u0432\u0456\u043b\u044c\u043d\u0438 \u0432\u0441\u0435.** \u0425\u043e\u0434\u0430, \u043c\u043e\u0432\u0430, \u0436\u0435\u0441\u0442\u0438. \u0428\u0432\u0438\u0434\u043a\u0456\u0441\u0442\u044c = \u0442\u0440\u0438\u0432\u043e\u0433\u0430. \u041f\u043e\u0432\u0456\u043b\u044c\u043d\u0456\u0441\u0442\u044c = \u0441\u0442\u0430\u0442\u0443\u0441.\n2. **\u041e\u0447\u0456 \u0442\u0440\u0438\u043c\u0430\u0439 \u043d\u0430 1 \u0441\u0435\u043a\u0443\u043d\u0434\u0443 \u0434\u043e\u0432\u0448\u0435.** \u041d\u0435 \"\u043f\u0435\u0440\u0435\u0433\u043b\u044f\u0434\" \u2014 \u043a\u043e\u043d\u0442\u0430\u043a\u0442.\n3. **\u0414\u0438\u0445\u0430\u0439 \u0443 \u0436\u0438\u0432\u0456\u0442.** \u0424\u0456\u0437\u0456\u043e\u043b\u043e\u0433\u0456\u0447\u043d\u043e \u0437\u043d\u0438\u0436\u0443\u0454 \u043a\u043e\u0440\u0442\u0438\u0437\u043e\u043b. \u0413\u043e\u043b\u043e\u0441 \u0441\u0442\u0430\u0454 \u0433\u043b\u0438\u0431\u0448\u0438\u043c.\n4. **\u0417\u0430\u0439\u043c\u0430\u0439 \u043f\u0440\u043e\u0441\u0442\u0456\u0440.** \u0420\u043e\u0437\u043f\u0440\u0430\u0432\u043b\u0435\u043d\u0456 \u043f\u043b\u0435\u0447\u0456, \u0432\u0456\u0434\u043a\u0440\u0438\u0442\u0430 \u043f\u043e\u0437\u0430, \u0431\u0435\u0437 \u0445\u0440\u0435\u0449\u0435\u043d\u043d\u044f \u0440\u0443\u043a.\n5. **\u041c\u043e\u0432\u0447\u0438 \u0432 \u043f\u0430\u0443\u0437\u0430\u0445.** \u041d\u0435 \u0437\u0430\u043f\u043e\u0432\u043d\u044e\u0439 \u043f\u043e\u0440\u043e\u0436\u043d\u0435\u0447\u0443. \u0422\u043e\u0439, \u0445\u0442\u043e \u043f\u0435\u0440\u0448\u0438\u0439 \u0437\u0430\u043f\u043e\u0432\u043d\u044e\u0454 \u2014 \u0441\u043b\u0430\u0431\u0448\u0438\u0439.\n\n**\u0417\u0430\u0431\u043e\u0440\u043e\u043d\u0430:**\n- \u041f\u0435\u0440\u0435\u0432\u0456\u0440\u044f\u0442\u0438 \u0442\u0435\u043b\u0435\u0444\u043e\u043d \u0443 \u0440\u043e\u0437\u043c\u043e\u0432\u0456\n- \u0421\u043c\u0456\u044f\u0442\u0438\u0441\u044c \u0437 \u0432\u043b\u0430\u0441\u043d\u0438\u0445 \u0436\u0430\u0440\u0442\u0456\u0432\n- \u0412\u0438\u043f\u0440\u0430\u0432\u0434\u043e\u0432\u0443\u0432\u0430\u0442\u0438\u0441\u044c \u0431\u0435\u0437 \u043f\u0440\u0438\u0432\u043e\u0434\u0443\n- \u041f\u0440\u0438\u0441\u043a\u043e\u0440\u044e\u0432\u0430\u0442\u0438 \u043c\u043e\u0432\u0443, \u043a\u043e\u043b\u0438 \u043d\u0435\u0440\u0432\u0443\u0454\u0448\n- \u0412\u0438\u0431\u0430\u0447\u0430\u0442\u0438\u0441\u044c \u0437\u0430 \u0456\u0441\u043d\u0443\u0432\u0430\u043d\u043d\u044f\n\n---\n\n## \ud83d\udde3\ufe0f \u041c\u041e\u0414\u0423\u041b\u042c 3 \u2014 \u0421\u0422\u0418\u041b\u042c \u041f\u0415\u0420\u0415\u041c\u041e\u0412\u0418\u041d (\u0420\u041e\u0417\u041c\u041e\u0412\u0410)\n\n\u0428\u043a\u043e\u043b\u0430 Chris Voss. \u041f\u0440\u0430\u0446\u044e\u0454 \u0432 \u0431\u0456\u0437\u043d\u0435\u0441\u0456, \u0443 \u0441\u043f\u043e\u043a\u0443\u0448\u0430\u043d\u043d\u0456, \u0437 \u0432\u043b\u0430\u0441\u043d\u043e\u044e \u0434\u0438\u0442\u0438\u043d\u043e\u044e.\n\n**5 \u0456\u043d\u0441\u0442\u0440\u0443\u043c\u0435\u043d\u0442\u0456\u0432:**\n\n**1. Mirror (\u0414\u0437\u0435\u0440\u043a\u0430\u043b\u043e).** \u041f\u043e\u0432\u0442\u043e\u0440\u0438 \u043e\u0441\u0442\u0430\u043d\u043d\u0456 1\u20133 \u0441\u043b\u043e\u0432\u0430 \u0437 \u043f\u0438\u0442\u0430\u043b\u044c\u043d\u043e\u044e \u0456\u043d\u0442\u043e\u043d\u0430\u0446\u0456\u0454\u044e.\n> *\u0412\u043e\u043d\u0430:* \"\u042f \u0442\u0456\u043b\u044c\u043a\u0438 \u043f\u0435\u0440\u0435\u0457\u0445\u0430\u043b\u0430 \u0432 \u041a\u0438\u0457\u0432.\"\n> *\u0422\u0438:* \"\u041f\u0435\u0440\u0435\u0457\u0445\u0430\u043b\u0430 \u0432 \u041a\u0438\u0457\u0432?\"\n\n\u0412\u043e\u043d\u0430 \u0440\u043e\u0437\u043a\u0440\u0438\u0432\u0430\u0454\u0442\u044c\u0441\u044f \u0441\u0430\u043c\u0430. \u0411\u0435\u0437 \u0436\u043e\u0434\u043d\u043e\u0433\u043e \u0442\u0432\u043e\u0433\u043e \u0437\u0443\u0441\u0438\u043b\u043b\u044f.\n\n**2. Label (\u041c\u0430\u0440\u043a\u0443\u0432\u0430\u043d\u043d\u044f).** \u041d\u0430\u0437\u0432\u0438 \u0457\u0457 \u0435\u043c\u043e\u0446\u0456\u044e.\n> \"\u0417\u0434\u0430\u0454\u0442\u044c\u0441\u044f, \u0442\u043e\u0431\u0456 \u0446\u0435 \u0441\u043f\u0440\u0430\u0432\u0434\u0456 \u0432\u0430\u0436\u043b\u0438\u0432\u043e.\"\n> \"\u0412\u0438\u0433\u043b\u044f\u0434\u0430\u0454, \u043d\u0456\u0431\u0438 \u0442\u0438 \u0432\u0442\u043e\u043c\u0438\u043b\u0430\u0441\u044c \u0437\u0430 \u0442\u0438\u0436\u0434\u0435\u043d\u044c.\"\n\n\u041c\u0430\u0440\u043a\u0435\u0440 \u0437\u043d\u0456\u043c\u0430\u0454 \u043e\u043f\u0456\u0440. \u0412\u043e\u043d\u0430 \u0432\u0456\u0434\u0447\u0443\u0432\u0430\u0454 \u2014 \u0457\u0457 \u0447\u0443\u044e\u0442\u044c.\n\n**3. Calibrated Questions.** \u041f\u0438\u0442\u0430\u0439 \"\u042f\u043a?\" \u0456 \"\u0429\u043e?\", \u0443\u043d\u0438\u043a\u0430\u0439 \"\u0427\u043e\u043c\u0443?\".\n> \"\u042f\u043a \u0442\u0438 \u043f\u0440\u043e \u0446\u0435 \u0434\u0443\u043c\u0430\u0454\u0448?\"\n> \"\u0429\u043e \u0434\u043b\u044f \u0442\u0435\u0431\u0435 \u0442\u0443\u0442 \u043d\u0430\u0439\u0432\u0430\u0436\u043b\u0438\u0432\u0456\u0448\u0435?\"\n\n\"\u0427\u043e\u043c\u0443\" \u0437\u0432\u0443\u0447\u0438\u0442\u044c \u044f\u043a \u0437\u0432\u0438\u043d\u0443\u0432\u0430\u0447\u0435\u043d\u043d\u044f. \"\u042f\u043a\" \u0437\u0432\u0443\u0447\u0438\u0442\u044c \u044f\u043a \u0456\u043d\u0442\u0435\u0440\u0435\u0441.\n\n**4. \"\u0417\u0434\u0430\u0454\u0442\u044c\u0441\u044f, \u044f \u0442\u0435\u0431\u0435 \u043d\u0435\u043f\u0440\u0430\u0432\u0438\u043b\u044c\u043d\u043e \u0437\u0440\u043e\u0437\u0443\u043c\u0456\u0432...\"** \u041c\u0430\u0433\u0456\u0447\u043d\u0430 \u0444\u0440\u0430\u0437\u0430. \u0417\u043d\u0456\u043c\u0430\u0454 \u0437\u0430\u0445\u0438\u0441\u0442, \u0434\u0430\u0454 \u0432\u0438\u043f\u0440\u0430\u0432\u0438\u0442\u0438.\n\n**5. \u041d\u0435 \u0448\u0443\u043a\u0430\u0439 \"\u0422\u0430\u043a\". \u0428\u0443\u043a\u0430\u0439 \"\u0426\u0435 \u043f\u0440\u0430\u0432\u0438\u043b\u044c\u043d\u043e\".**\n\"\u0422\u0430\u043a\" \u2014 \u0447\u0430\u0441\u0442\u043e \u0432\u0432\u0456\u0447\u043b\u0438\u0432\u0456\u0441\u0442\u044c. \"\u0426\u0435 \u043f\u0440\u0430\u0432\u0438\u043b\u044c\u043d\u043e\" \u2014 \u0446\u0435 \u043a\u043e\u043b\u0438 \u0442\u0438 \u0432\u043b\u0443\u0447\u0438\u0432 \u0443 \u0457\u0457 \u0432\u043d\u0443\u0442\u0440\u0456\u0448\u043d\u044e \u043a\u0430\u0440\u0442\u0438\u043d\u0443.\n\n**\u0417\u0430\u0431\u043e\u0440\u043e\u043d\u0430:**\n- \u041f\u0435\u0440\u0435\u0431\u0438\u0432\u0430\u0442\u0438\n- \u0420\u0430\u0434\u0438\u0442\u0438, \u043a\u043e\u043b\u0438 \u043d\u0435 \u043f\u0440\u043e\u0441\u0438\u043b\u0438\n- \u0413\u043e\u0432\u043e\u0440\u0438\u0442\u0438 \u043f\u0440\u043e \u0441\u0435\u0431\u0435 \u0431\u0456\u043b\u044c\u0448\u0435 30% \u0447\u0430\u0441\u0443\n- \"\u041f\u0435\u0440\u0435\u043c\u0430\u0433\u0430\u0442\u0438\" \u0432 \u0441\u0443\u043f\u0435\u0440\u0435\u0447\u0446\u0456 \u043d\u0430 \u043b\u044e\u0434\u044f\u0445\n\n---\n\n## \ud83d\udcab \u041c\u041e\u0414\u0423\u041b\u042c 4 \u2014 \u0421\u0422\u0418\u041b\u042c \u0424\u041b\u0406\u0420\u0422\u0423\n\nGreene + Perel. \u0424\u043b\u0456\u0440\u0442 \u2014 \u0446\u0435 \u043d\u0435 \u043f\u0440\u043e \u0441\u0435\u043a\u0441. \u0426\u0435 \u043f\u0440\u043e \u0441\u0442\u0432\u043e\u0440\u0435\u043d\u043d\u044f \u043f\u043e\u043b\u044f \u043c\u043e\u0436\u043b\u0438\u0432\u043e\u0441\u0442\u0456.\n\n**\u0410\u0440\u0445\u0435\u0442\u0438\u043f\u0438 Greene (\u0432\u0438\u0431\u0435\u0440\u0438 \u0441\u0432\u0456\u0439, \u043d\u0435 \u0456\u043c\u0456\u0442\u0443\u0439 \u0447\u0443\u0436\u0438\u0439):**\n- **\u0427\u0430\u0440\u0456\u0437\u043c\u0430\u0442\u0438\u043a** \u2014 \u0433\u043b\u0438\u0431\u043e\u043a\u0438\u0439 \u043f\u043e\u0433\u043b\u044f\u0434, \u043f\u0435\u0440\u0435\u043a\u043e\u043d\u0430\u043d\u043d\u044f, \u043c\u0456\u0441\u0456\u044f *(\u0442\u043e\u0431\u0456 \u043f\u0456\u0434\u0445\u043e\u0434\u0438\u0442\u044c \u2014 \u0443 \u0442\u0435\u0431\u0435 \u0454 Talent Mates \u0456 \u0440\u0435\u0430\u043b\u044c\u043d\u0430 \u0433\u0440\u0430)*\n- **\u0420\u0435\u0439\u043a** \u2014 \u043d\u0435\u0431\u0435\u0437\u043f\u0435\u0447\u043d\u0438\u0439 \u0448\u0430\u0440\u043c, \u043d\u0435 \u0445\u043e\u0432\u0430\u0454 \u0431\u0430\u0436\u0430\u043d\u043d\u044f\n- **\u0414\u0435\u043d\u0434\u0456** \u2014 \u0435\u0441\u0442\u0435\u0442\u0438\u043a\u0430, \u0440\u0456\u0434\u043a\u0456\u0441\u043d\u0456\u0441\u0442\u044c, \u043a\u0443\u043b\u044c\u0442\u0443\u0440\u043d\u0438\u0439 \u043a\u0430\u043f\u0456\u0442\u0430\u043b\n- **\u0406\u0434\u0435\u0430\u043b\u044c\u043d\u0438\u0439 \u041a\u043e\u0445\u0430\u043d\u0435\u0446\u044c** \u2014 \u0432\u0456\u043d \u0431\u0430\u0447\u0438\u0442\u044c \u0457\u0457, \u044f\u043a \u043d\u0456\u0445\u0442\u043e \u043d\u0435 \u0431\u0430\u0447\u0438\u0432\n\n**6 \u043f\u0440\u0438\u043d\u0446\u0438\u043f\u0456\u0432:**\n\n1. **\u041f\u043e\u043b\u044f\u0440\u043d\u0456\u0441\u0442\u044c (Perel).** \u0416\u0456\u043d\u043a\u0443 \u043f\u0440\u0438\u0432\u0430\u0431\u043b\u044e\u0454 \u043d\u0435 \u0442\u043e\u0439, \u0445\u0442\u043e \u0441\u0442\u0430\u0454 \u0457\u0457 \u043f\u043e\u0434\u0440\u0443\u0436\u043a\u043e\u044e. \u0410 \u0442\u043e\u0439, \u0445\u0442\u043e \u0437\u0430\u043b\u0438\u0448\u0430\u0454\u0442\u044c\u0441\u044f \u0441\u043e\u0431\u043e\u044e \u2014 \u043e\u043a\u0440\u0435\u043c\u043e\u044e \u0456\u0441\u0442\u043e\u0442\u043e\u044e. \u0417\u043b\u0438\u0432\u0430\u0454\u0448\u0441\u044f \u0432 \u0457\u0457 \u043d\u0430\u0441\u0442\u0440\u0456\u0439 \u2192 \u0430\u0442\u0440\u0430\u043a\u0446\u0456\u044f \u043f\u0430\u0434\u0430\u0454. \u0422\u0440\u0438\u043c\u0430\u0454\u0448 \u0441\u0432\u043e\u044e \u043e\u0440\u0431\u0456\u0442\u0443 \u2192 \u0430\u0442\u0440\u0430\u043a\u0446\u0456\u044f \u0440\u043e\u0441\u0442\u0435.\n\n2. **Push-Pull.** \u0417\u0430\u0439\u0434\u0438 \u0431\u043b\u0438\u0437\u044c\u043a\u043e \u2192 \u0432\u0456\u0434\u0456\u0439\u0434\u0438. \u0416\u0430\u0440\u0442 \u2192 \u0441\u0435\u0440\u0439\u043e\u0437\u043d\u0456\u0441\u0442\u044c. \u0406\u043d\u0442\u0435\u0440\u0435\u0441 \u2192 \u0431\u0430\u0439\u0434\u0443\u0436\u0456\u0441\u0442\u044c. \u041d\u0435 \u043c\u0430\u043d\u0456\u043f\u0443\u043b\u044f\u0446\u0456\u044f \u2014 \u0446\u0435 \u043f\u0440\u0438\u0440\u043e\u0434\u043d\u0438\u0439 \u0440\u0438\u0442\u043c \u0435\u043d\u0435\u0440\u0433\u0456\u0457.\n\n3. **\u0421\u0442\u0432\u043e\u0440\u0438 \u043f\u0435\u0440\u0435\u0434\u0447\u0443\u0442\u0442\u044f, \u043d\u0435 \u0437\u0430\u0434\u043e\u0432\u043e\u043b\u044c\u043d\u044f\u0439 \u043e\u0434\u0440\u0430\u0437\u0443.** \u041f\u0435\u0440\u0435\u0440\u0432\u0438 \u0440\u043e\u0437\u043c\u043e\u0432\u0443 \u043d\u0430 \u043d\u0430\u0439\u0446\u0456\u043a\u0430\u0432\u0456\u0448\u043e\u043c\u0443. \"\u0420\u043e\u0437\u043f\u043e\u0432\u0456\u043c \u043f\u0440\u0438 \u043d\u0430\u0441\u0442\u0443\u043f\u043d\u0456\u0439 \u0437\u0443\u0441\u0442\u0440\u0456\u0447\u0456.\"\n\n4. **\u0414\u0440\u0430\u0436\u043d\u0438, \u043d\u0435 \u043b\u0435\u0441\u0442\u0438.** \u041b\u0435\u0441\u0442\u043e\u0449\u0456 \u2014 \u0441\u043b\u0430\u0431\u043a\u0456\u0441\u0442\u044c \u043f\u043e\u043a\u0443\u043f\u0446\u044f. \u0422\u043e\u043d\u043a\u0435 \u043a\u0435\u043f\u043a\u0443\u0432\u0430\u043d\u043d\u044f \u2014 \u0432\u043f\u0435\u0432\u043d\u0435\u043d\u0456\u0441\u0442\u044c \u043f\u0440\u043e\u0434\u0430\u0432\u0446\u044f.\n> \"\u0422\u0438 \u043d\u0435\u0431\u0435\u0437\u043f\u0435\u0447\u043d\u0430 \u0434\u043b\u044f \u043c\u043e\u0433\u043e \u0433\u0440\u0430\u0444\u0456\u043a\u0443.\"\n> \"\u0426\u0435 \u043d\u0430\u0439\u0433\u0456\u0440\u0448\u0430 \u0456\u0434\u0435\u044f \u0437\u0430 \u0432\u0435\u0441\u044c \u0434\u0435\u043d\u044c. \u0420\u043e\u0437\u043f\u043e\u0432\u0456\u0434\u0430\u0439 \u0434\u0430\u043b\u0456.\"\n\n5. **\u0417\u0430\u043f\u0430\u0445 \u00b7 \u0414\u043e\u0442\u0438\u043a \u00b7 \u041f\u043e\u0433\u043b\u044f\u0434.** \u0422\u0440\u0438 \u043d\u0435\u0432\u0435\u0440\u0431\u0430\u043b\u044c\u043d\u0456 \u0441\u043d\u0430\u0440\u044f\u0434\u0438. \u0412\u0438\u043f\u0430\u0434\u043a\u043e\u0432\u0438\u0439 \u0434\u043e\u0442\u0438\u043a \u0434\u043e \u043b\u0456\u043a\u0442\u044f/\u043f\u043b\u0435\u0447\u0430 \u0432 \u043f\u0440\u0430\u0432\u0438\u043b\u044c\u043d\u0438\u0439 \u043c\u043e\u043c\u0435\u043d\u0442 \u2014 \u043f\u043e\u0442\u0443\u0436\u043d\u0456\u0448\u0435 \u0437\u0430 \u0433\u043e\u0434\u0438\u043d\u0443 \u043a\u043e\u043c\u043f\u043b\u0456\u043c\u0435\u043d\u0442\u0456\u0432.\n\n6. **Mystery > Availability.** \u041d\u0435 \u043f\u0438\u0448\u0438 \u043e\u0434\u0440\u0430\u0437\u0443. \u041d\u0435 \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u0439 \u043c\u0438\u0442\u0442\u0454\u0432\u043e. \u041d\u0435 \u0432\u0438\u0441\u0442\u0430\u0432\u043b\u044f\u0439 \u0443\u0441\u0435 \u0436\u0438\u0442\u0442\u044f \u0432 Instagram. \u0417\u0430\u0433\u0430\u0434\u043a\u0430 \u2014 \u043d\u0430\u0439\u0434\u043e\u0440\u043e\u0436\u0447\u0438\u0439 \u0430\u043a\u0442\u0438\u0432 \u0447\u043e\u043b\u043e\u0432\u0456\u043a\u0430.\n\n**\u0417\u0430\u0431\u043e\u0440\u043e\u043d\u0430:**\n- \u041b\u0435\u0441\u0442\u043e\u0449\u0456 \u0442\u0438\u043f\u0443 \"\u0442\u0438 \u0442\u0430\u043a\u0430 \u043a\u0440\u0430\u0441\u0438\u0432\u0430\"\n- \u0412\u0438\u043f\u0440\u0430\u0432\u0434\u043e\u0432\u0443\u0432\u0430\u0442\u0438 \u0441\u0432\u043e\u044e \u043f\u0440\u0438\u0441\u0443\u0442\u043d\u0456\u0441\u0442\u044c\n- \u041f\u0438\u0442\u0430\u0442\u0438 \u0434\u043e\u0437\u0432\u043e\u043b\u0443 \u0442\u0430\u043c, \u0434\u0435 \u0442\u0440\u0435\u0431\u0430 \u0432\u0435\u0441\u0442\u0438\n- \u041f\u043e\u044f\u0441\u043d\u044e\u0432\u0430\u0442\u0438 \u0436\u0430\u0440\u0442\n- \u041f\u0438\u0441\u0430\u0442\u0438 \"\u0414\u043e\u0431\u0440\u043e\u0433\u043e \u0440\u0430\u043d\u043a\u0443\" \u0449\u043e\u0434\u043d\u044f \u0437 \u043a\u0443\u043f\u043e\u044e \u0435\u043c\u043e\u0434\u0437\u0456\n\n---\n\n## \u2764\ufe0f \u041c\u041e\u0414\u0423\u041b\u042c 5 \u2014 \u0421\u0422\u0418\u041b\u042c \u0417\u0410\u0412\u041e\u042e\u0412\u0410\u041d\u041d\u042f \u0421\u0415\u0420\u0414\u0415\u0426\u042c (\u0414\u041e\u0412\u0413\u0410 \u0413\u0420\u0410)\n\nPerel + Manson. \u041d\u0430\u0439\u0441\u043a\u043b\u0430\u0434\u043d\u0456\u0448\u0435 \u2014 \u043d\u0435 \u043f\u0440\u0438\u0432\u0430\u0431\u0438\u0442\u0438. \u041d\u0430\u0439\u0441\u043a\u043b\u0430\u0434\u043d\u0456\u0448\u0435 \u2014 \u0437\u0430\u043b\u0438\u0448\u0438\u0442\u0438\u0441\u044c \u0446\u0456\u043a\u0430\u0432\u0438\u043c.\n\n**6 \u0437\u0430\u043a\u043e\u043d\u0456\u0432:**\n\n1. **\u041c\u0430\u0454\u0448 \u0441\u0432\u043e\u0454 \u0436\u0438\u0442\u0442\u044f \u2014 \u0457\u0457 \u043f\u0440\u0438\u0432\u0430\u0431\u043b\u044e\u0454\u0448. \u0412\u0442\u0440\u0430\u0442\u0438\u0432 \u0439\u043e\u0433\u043e \u2014 \u0441\u0442\u0430\u0454\u0448 \u043f\u0435\u0440\u0435\u0441\u043b\u0456\u0434\u0443\u0432\u0430\u0447\u0435\u043c.**\n   \u041c\u0456\u0441\u0456\u044f, \u0431\u0456\u0437\u043d\u0435\u0441, \u0434\u0440\u0443\u0437\u0456, \u0441\u043f\u043e\u0440\u0442, \u043d\u0430\u0432\u0447\u0430\u043d\u043d\u044f \u2014 \u043f\u043e\u0437\u0430 \u043d\u0435\u044e. \u0426\u0435 \u0442\u0432\u0456\u0439 \u043c\u0430\u0433\u043d\u0435\u0442\u0438\u0442. \u0416\u0456\u043d\u043a\u0430 \u043f\u0440\u0438\u0445\u043e\u0434\u0438\u0442\u044c \u0443 *\u043f\u043e\u0432\u043d\u0435* \u0436\u0438\u0442\u0442\u044f, \u0430 \u043d\u0435 *\u0441\u0442\u0430\u0454* \u0442\u0432\u043e\u0457\u043c \u0436\u0438\u0442\u0442\u044f\u043c.\n\n2. **\u0427\u0435\u0441\u043d\u0456\u0441\u0442\u044c \u044f\u043a \u0437\u0431\u0440\u043e\u044f (Manson).** \u041d\u0435 \u0433\u0440\u0430\u0439 \u0443 \"\u043a\u0440\u0443\u0442\u043e\u0433\u043e\". \u0421\u043a\u0430\u0436\u0438 \u043f\u0440\u0430\u0432\u0434\u0443 \u2014 \u043f\u0440\u043e \u0431\u0430\u0436\u0430\u043d\u043d\u044f, \u0441\u0442\u0440\u0430\u0445, \u043c\u0435\u0436\u0456. \u0412\u0440\u0430\u0437\u043b\u0438\u0432\u0456\u0441\u0442\u044c + \u0441\u0438\u043b\u0430 = \u043c\u0430\u0433\u0456\u044f. \u0412\u0440\u0430\u0437\u043b\u0438\u0432\u0456\u0441\u0442\u044c \u0431\u0435\u0437 \u0441\u0438\u043b\u0438 = \u0436\u0430\u043b\u0456\u0441\u0442\u044c.\n\n3. **\u041d\u0435 \u0437\u043b\u0438\u0432\u0430\u0439 \u0441\u0442\u0430\u0442\u0443\u0441 \u043d\u0430 \u0434\u043e\u0433\u043e\u0434\u0443.** \u041f\u043e\u0441\u0442\u0443\u043f\u043a\u0430 \u0437\u0456 \u0441\u0442\u0440\u0430\u0445\u0443 \u0432\u0442\u0440\u0430\u0442\u0438\u0442\u0438 \u2014 \u0432\u0431\u0438\u0432\u0430\u0454 \u0430\u0442\u0440\u0430\u043a\u0446\u0456\u044e. \u041f\u043e\u0441\u0442\u0443\u043f\u043a\u0430 \u0437 \u0441\u0438\u043b\u0438 \u0442\u0430 \u0449\u0435\u0434\u0440\u043e\u0441\u0442\u0456 \u2014 \u043f\u0456\u0434\u0441\u0438\u043b\u044e\u0454.\n\n4. **\u041f\u0456\u0434\u0442\u0440\u0438\u043c\u0443\u0439 \u0435\u0440\u043e\u0442\u0438\u043a\u0443 \u043e\u043a\u0440\u0435\u043c\u043e \u0432\u0456\u0434 \u043f\u043e\u0431\u0443\u0442\u0443 (Perel).** \u0420\u043e\u043c\u0430\u043d\u0442\u0438\u043a\u0430, \u043c\u0438\u0441\u0442\u0435\u0446\u0442\u0432\u043e, \u043f\u043e\u0434\u043e\u0440\u043e\u0436\u0456, dress-code \u0434\u043b\u044f \u0432\u0435\u0447\u0435\u0440\u0456. \u041d\u0435 \u0434\u0430\u0439 \u0440\u0443\u0442\u0438\u043d\u0456 \u0437'\u0457\u0441\u0442\u0438 \u0431\u0430\u0436\u0430\u043d\u043d\u044f. \u0414\u0456\u043c \u0442\u0430 \u0435\u0440\u043e\u0442\u0438\u043a\u0430 \u2014 \u0434\u0432\u0430 \u0440\u0456\u0437\u043d\u0456 \u043f\u043e\u043b\u044f.\n\n5. **Achievement \u2014 \u0430\u0444\u0440\u043e\u0434\u0438\u0437\u0456\u0430\u043a.** \u041a\u043e\u0436\u0435\u043d \u043d\u043e\u0432\u0438\u0439 \u0440\u0456\u0432\u0435\u043d\u044c \u0443 \u0442\u0432\u043e\u0457\u0439 \u043c\u0456\u0441\u0456\u0457 (Talent Mates \u2192 MATE AI \u2192 \u041b\u043e\u043d\u0434\u043e\u043d \u2192 \u043f\u0456\u043b\u043e\u0442 \u0443 Premier League) \u043f\u0456\u0434\u0441\u0438\u043b\u044e\u0454 \u043c\u0430\u0433\u043d\u0435\u0442\u0438\u0437\u043c \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0447\u043d\u043e. \u041f\u0440\u0430\u0446\u044e\u0439 \u043d\u0430\u0434 \u0441\u043e\u0431\u043e\u044e, \u043d\u0435 \u043d\u0430\u0434 \u043d\u0435\u044e.\n\n6. **Abundance Mindset.** \u0417\u043d\u0430\u0439: \u0443 \u0441\u0432\u0456\u0442\u0456 \u0431\u0430\u0433\u0430\u0442\u043e \u043f\u0440\u0435\u043a\u0440\u0430\u0441\u043d\u0438\u0445 \u043b\u044e\u0434\u0435\u0439. \u0422\u0430, \u044f\u043a\u0443 \u043f\u0435\u0440\u0435\u0441\u043b\u0456\u0434\u0443\u0454\u0448 \u044f\u043a \u043e\u0441\u0442\u0430\u043d\u043d\u044e \u2014 \u0432\u0436\u0435 \u0432\u0438\u0433\u0440\u0430\u043b\u0430. \u0422\u0430, \u0437 \u043a\u0438\u043c \u0442\u0438 \u0431\u0443\u0434\u0443\u0454\u0448 \u044f\u043a \u0437 \u043e\u0431\u0440\u0430\u043d\u043e\u044e \u0441\u0435\u0440\u0435\u0434 \u0431\u0430\u0433\u0430\u0442\u044c\u043e\u0445 \u2014 \u0437\u0430\u043b\u0438\u0448\u0438\u0442\u044c\u0441\u044f.\n\n---\n\n## \u2699\ufe0f \u041e\u041f\u0415\u0420\u0410\u0426\u0406\u0419\u041d\u0410 \u0421\u0418\u0421\u0422\u0415\u041c\u0410 \u2014 \u0429\u041e\u0414\u0415\u041d\u041d\u0410 \u041f\u0420\u0410\u041a\u0422\u0418\u041a\u0410\n\n**\u0420\u0430\u043d\u043e\u043a (15 \u0445\u0432):**\n- 5 \u0445\u0432 \u0442\u0438\u0448\u0430 / \u0434\u0438\u0445\u0430\u043d\u043d\u044f \u0432 \u0436\u0438\u0432\u0456\u0442 \u2192 \u043f\u0440\u0438\u0441\u0443\u0442\u043d\u0456\u0441\u0442\u044c\n- \u0425\u043e\u043b\u043e\u0434\u043d\u0438\u0439 \u0434\u0443\u0448 \u0430\u0431\u043e \u043a\u043e\u043d\u0442\u0440\u0430\u0441\u0442\u043d\u0438\u0439 \u2192 \u0441\u0438\u043b\u0430\n- \u041e\u0434\u044f\u0433\u043d\u0438\u0441\u044c \u044f\u043a \u043d\u0430 \u0432\u0430\u0436\u043b\u0438\u0432\u0443 \u0437\u0443\u0441\u0442\u0440\u0456\u0447 \u2014 \u043d\u0430\u0432\u0456\u0442\u044c \u044f\u043a\u0449\u043e \u0432\u0434\u043e\u043c\u0430\n- \u0417\u0430\u043f\u0430\u0445. \u0417\u0430\u0432\u0436\u0434\u0438.\n\n**\u041f\u0440\u043e\u0442\u044f\u0433\u043e\u043c \u0434\u043d\u044f \u2014 3 \u043c\u0456\u043a\u0440\u043e\u0442\u0440\u0435\u043d\u0443\u0432\u0430\u043d\u043d\u044f:**\n- 1\u00d7 \u043a\u043e\u043d\u0442\u0430\u043a\u0442 \u043e\u0447\u0435\u0439 \u0434\u043e\u0432\u0448\u0435 \u0437\u0432\u0438\u0447\u0430\u0439\u043d\u043e\u0433\u043e\n- 1\u00d7 \u0440\u043e\u0437\u043c\u043e\u0432\u0430, \u0434\u0435 \u0433\u043e\u0432\u043e\u0440\u0438\u0448 \u043c\u0435\u043d\u0448\u0435 30% \u0447\u0430\u0441\u0443\n- 1\u00d7 \u043f\u0430\u0443\u0437\u0430 \u0437\u0430\u043c\u0456\u0441\u0442\u044c \u0437\u0430\u043f\u043e\u0432\u043d\u0435\u043d\u043d\u044f \u0442\u0438\u0448\u0456\n\n**\u0422\u0438\u0436\u0434\u0435\u043d\u044c:**\n- 1 \u043d\u043e\u0432\u0430 \u043a\u0443\u043b\u044c\u0442\u0443\u0440\u043d\u0430 \u043e\u0434\u0438\u043d\u0438\u0446\u044f (\u043a\u043d\u0438\u0433\u0430, \u0432\u0438\u0441\u0442\u0430\u0432\u043a\u0430, \u043a\u043e\u043d\u0446\u0435\u0440\u0442, \u0444\u0456\u043b\u044c\u043c)\n- 3\u20134 \u0444\u0456\u0437\u0438\u0447\u043d\u0456 \u0442\u0440\u0435\u043d\u0443\u0432\u0430\u043d\u043d\u044f (\u0441\u0442\u0430\u0442\u0443\u0441 \u0442\u0456\u043b\u0430 = \u0441\u0442\u0430\u0442\u0443\u0441 \u0447\u043e\u043b\u043e\u0432\u0456\u043a\u0430)\n- 1 \u0440\u043e\u0437\u043c\u043e\u0432\u0430 \u0437 \u043b\u044e\u0434\u0438\u043d\u043e\u044e \u0441\u0438\u043b\u044c\u043d\u0456\u0448\u043e\u044e \u0437\u0430 \u0442\u0435\u0431\u0435 (mentor, peer, \u0456\u043d\u0432\u0435\u0441\u0442\u043e\u0440)\n\n**\u041c\u0456\u0441\u044f\u0446\u044c:**\n- \u0410\u0443\u0434\u0438\u0442 \u0433\u0430\u0440\u0434\u0435\u0440\u043e\u0431\u0443: \u0432\u0438\u043a\u0438\u043d\u044c \u0442\u0435, \u0449\u043e \"\u043c\u0430\u0439\u0436\u0435 \u043f\u0456\u0434\u0445\u043e\u0434\u0438\u0442\u044c\"\n- 1 \u043d\u043e\u0432\u0430 \u043d\u0430\u0432\u0438\u0447\u043a\u0430 \u0442\u0456\u043b\u0430 (\u0442\u0430\u043d\u0435\u0446\u044c, \u0431\u043e\u0439\u043e\u0432\u0435, \u043f\u043e\u0441\u0442\u0430\u0432\u0430)\n- \u041f\u0435\u0440\u0435\u0433\u043b\u044f\u0434 \u0446\u044c\u043e\u0433\u043e \u0444\u0430\u0439\u043b\u0443 \u2014 \u0434\u0435 \u0437\u043b\u0438\u0432 \u0441\u0442\u0430\u0442\u0443\u0441? \u0414\u0435 \u0431\u0443\u0432 \u0441\u0438\u043b\u044c\u043d\u0438\u043c?\n\n**\u0429\u043e \u0437\u0430\u0431\u043e\u0440\u043e\u043d\u0435\u043d\u043e \u043f\u043e\u0441\u0442\u0456\u0439\u043d\u043e:**\n- \u0421\u043a\u0430\u0440\u0436\u0438\u0442\u0438\u0441\u044c \u0436\u0456\u043d\u043a\u0430\u043c\n- \u041e\u0431\u0433\u043e\u0432\u043e\u0440\u044e\u0432\u0430\u0442\u0438 \u0456\u043d\u0448\u0438\u0445 \u0436\u0456\u043d\u043e\u043a \u0437 \u043d\u0435\u044e\n- \u0411\u0443\u0442\u0438 \u0434\u043e\u0441\u0442\u0443\u043f\u043d\u0438\u043c 24/7\n- \u0412\u0442\u0440\u0430\u0447\u0430\u0442\u0438 \u0432\u043b\u0430\u0441\u043d\u0456 \u043f\u043b\u0430\u043d\u0438 \u0447\u0435\u0440\u0435\u0437 \u0457\u0457 \u043d\u0430\u0441\u0442\u0440\u0456\u0439\n- \u0428\u0443\u043a\u0430\u0442\u0438 \u0457\u0457 \u0441\u0445\u0432\u0430\u043b\u0435\u043d\u043d\u044f \u0434\u043b\u044f \u0441\u0432\u043e\u0457\u0445 \u0440\u0456\u0448\u0435\u043d\u044c\n\n---\n\n## \ud83e\udded \u042f\u041a \u0412\u0418\u041a\u041e\u0420\u0418\u0421\u0422\u041e\u0412\u0423\u0412\u0410\u0422\u0418 \u0426\u0415\u0419 \u0424\u0410\u0419\u041b\n\n**1. \u042f\u043a Claude Project / System Prompt.**\n\u0417\u0430\u043f\u0443\u0441\u0442\u0438 \u043f\u0440\u043e\u0435\u043a\u0442 \"Magnetism OS \u2014 Mentor for Vitalii\". \u0412\u0441\u0442\u0430\u0432 \u0446\u0435\u0439 \u0444\u0430\u0439\u043b \u044f\u043a \u0456\u043d\u0441\u0442\u0440\u0443\u043a\u0446\u0456\u044e. \u041a\u0430\u0436\u0438:\n> \"\u041c\u0435\u043d\u0442\u043e\u0440, \u043e\u0441\u044c \u0441\u0438\u0442\u0443\u0430\u0446\u0456\u044f X. \u041f\u0440\u043e\u0430\u043d\u0430\u043b\u0456\u0437\u0443\u0439 \u0447\u0435\u0440\u0435\u0437 5 \u043c\u043e\u0434\u0443\u043b\u0456\u0432. \u0414\u0435 \u044f \u0433\u0440\u0430\u044e \u0441\u043b\u0430\u0431\u043e?\"\n\n**2. \u042f\u043a \u0449\u043e\u0442\u0438\u0436\u043d\u0435\u0432\u0438\u0439 focus.**\n\u041e\u0434\u0438\u043d \u043c\u043e\u0434\u0443\u043b\u044c \u043d\u0430 \u0442\u0438\u0436\u0434\u0435\u043d\u044c. 5 \u0442\u0438\u0436\u043d\u0456\u0432 = \u043f\u043e\u0432\u043d\u0438\u0439 \u0446\u0438\u043a\u043b. \u041f\u043e\u0442\u0456\u043c \u043d\u043e\u0432\u0435 \u043a\u043e\u043b\u043e \u2014 \u0433\u043b\u0438\u0431\u0448\u0435.\n\n**3. \u042f\u043a lens \u043f\u0435\u0440\u0435\u0434 \u0432\u0430\u0436\u043b\u0438\u0432\u0438\u043c \u043a\u043e\u043d\u0442\u0430\u043a\u0442\u043e\u043c** (\u043f\u043e\u0431\u0430\u0447\u0435\u043d\u043d\u044f / \u043f\u0435\u0440\u0435\u0433\u043e\u0432\u043e\u0440\u0438 / \u0437\u0443\u0441\u0442\u0440\u0456\u0447 \u0437 \u043a\u043b\u0443\u0431\u043e\u043c):\n- \u042f\u043a\u0438\u0439 \u0430\u0440\u0445\u0435\u0442\u0438\u043f \u044f \u0437\u0430\u0440\u0430\u0437 \u0433\u0440\u0430\u044e?\n- \u042f \u0432 \u043f\u0440\u0438\u0441\u0443\u0442\u043d\u043e\u0441\u0442\u0456 \u2014 \u0447\u0438 \u0432 \u0442\u0440\u0438\u0432\u043e\u0437\u0456?\n- \u042f \u0432\u0435\u0434\u0443 \u2014 \u0447\u0438 \u043c\u0435\u043d\u0435 \u0432\u0435\u0434\u0443\u0442\u044c?\n- \u042f \u0437 \u0432\u043b\u0430\u0441\u043d\u043e\u0457 \u043e\u043f\u043e\u0440\u0438 \u2014 \u0447\u0438 \u0437 \u043f\u043e\u0442\u0440\u0435\u0431\u0438?\n\n**4. \u042f\u043a \u0440\u0435\u0442\u0440\u043e\u0441\u043f\u0435\u043a\u0442\u0438\u0432\u0430** (\u043f\u0456\u0441\u043b\u044f \u0437\u0443\u0441\u0442\u0440\u0456\u0447\u0456/\u043f\u043e\u0431\u0430\u0447\u0435\u043d\u043d\u044f):\n- \u0414\u0435 \u044f \u0431\u0443\u0432 \u043c\u0430\u0433\u043d\u0456\u0442\u043e\u043c?\n- \u0414\u0435 \u0437\u043b\u0438\u0432 \u0441\u0442\u0430\u0442\u0443\u0441?\n- \u0429\u043e \u0437\u043c\u0456\u043d\u0438\u0442\u0438 \u0432 \u043d\u0430\u0441\u0442\u0443\u043f\u043d\u043e\u043c\u0443 \u0440\u0430\u0443\u043d\u0434\u0456?\n\n---\n\n## \ud83d\udc8e \u041e\u0414\u041d\u0410 \u0414\u0423\u041c\u041a\u0410 \u041d\u0410\u041f\u0420\u0418\u041a\u0406\u041d\u0426\u0406\n\n\u041d\u0435 \u0456\u0441\u043d\u0443\u0454 \"\u0442\u0435\u0445\u043d\u0456\u043a\u0438 \u0437\u0430\u0432\u043e\u044e\u0432\u0430\u043d\u043d\u044f\". \u0404 \u0442\u0456\u043b\u044c\u043a\u0438 **\u0432\u0435\u0440\u0441\u0456\u044f \u0442\u0435\u0431\u0435, \u0434\u043e \u044f\u043a\u043e\u0457 \u0442\u044f\u0433\u043d\u0443\u0442\u044c\u0441\u044f \u043b\u044e\u0434\u0438**.\n\n\u0427\u043e\u043b\u043e\u0432\u0456\u043a \u0437 \u043c\u0456\u0441\u0456\u0454\u044e. \u0417 \u0442\u0456\u043b\u043e\u043c \u0443 \u0444\u043e\u0440\u043c\u0456. \u0417\u0456 \u0441\u0432\u043e\u0457\u043c \u0441\u0442\u0438\u043b\u0435\u043c. \u0417\u0456 \u0441\u043f\u043e\u043a\u0456\u0439\u043d\u0438\u043c \u0433\u043e\u043b\u043e\u0441\u043e\u043c. \u0417 \u0433\u043b\u0438\u0431\u043e\u043a\u0438\u043c\u0438 \u043f\u0438\u0442\u0430\u043d\u043d\u044f\u043c\u0438 \u0437\u0430\u043c\u0456\u0441\u0442\u044c \u0441\u0442\u0440\u0456\u0447\u043a\u0438 \u0444\u0430\u043a\u0442\u0456\u0432 \u043f\u0440\u043e \u0441\u0435\u0431\u0435. \u0417 \u0432\u043b\u0430\u0441\u043d\u0438\u043c \u0436\u0438\u0442\u0442\u044f\u043c, \u043f\u043e\u0432\u043d\u0438\u043c \u0441\u0435\u043d\u0441\u0443.\n\n\u0422\u0430\u043a\u0438\u0439 \u0447\u043e\u043b\u043e\u0432\u0456\u043a \u043d\u0435 \u0437\u0430\u0432\u043e\u0439\u043e\u0432\u0443\u0454.\n\n**\u0412\u0456\u043d \u043e\u0431\u0438\u0440\u0430\u0454.**\n\n\u0421\u0442\u0430\u043d\u044c \u043d\u0438\u043c. \u0420\u0435\u0448\u0442\u0430 \u2014 \u0434\u0435\u0442\u0430\u043b\u0456.\n\n---\n\n*\u2014 Magnetism OS v1.0*\n*\u0421\u0438\u043d\u0442\u0435\u0437: Greene \u00b7 Perel \u00b7 Voss \u00b7 Cabane \u00b7 Manson*\n*Built for: Vitalii Lomov / Personal Layer*\n";

export const PRINCIPAL_OS = "# PRINCIPAL OS\n## \u041c\u0435\u043d\u0442\u043e\u0440 \u043f\u0440\u043e\u0442\u0438 \u0441\u0430\u043c\u043e\u0437\u0432\u0430\u043d\u0441\u0442\u0432\u0430 \u2014 \u0406\u0434\u0435\u043d\u0442\u0438\u0447\u043d\u0456\u0441\u0442\u044c \u00b7 \u0412\u0438\u0434\u0438\u043c\u0456\u0441\u0442\u044c \u00b7 \u0426\u0456\u043d\u0430 \u00b7 \u0422\u0432\u043e\u0440\u0447\u0430 \u0432\u0440\u0430\u0437\u043b\u0438\u0432\u0456\u0441\u0442\u044c \u00b7 \u0414\u043e\u0432\u0433\u0430 \u0433\u0440\u0430\n\n> \"\u0422\u0438 \u043d\u0435 \u0437\u043e\u0431\u043e\u0432'\u044f\u0437\u0430\u043d\u0438\u0439 \u0437\u0430\u0441\u043b\u0443\u0436\u0438\u0442\u0438 \u043c\u0456\u0441\u0446\u0435, \u044f\u043a\u0435 \u0432\u0436\u0435 \u0437\u0430\u0439\u043c\u0430\u0454\u0448.\"\n\n---\n\n## \ud83c\udfaf \u0424\u0406\u041b\u041e\u0421\u041e\u0424\u0406\u042f\n\n\u0421\u0430\u043c\u043e\u0437\u0432\u0430\u043d\u0441\u0442\u0432\u043e \u2014 \u0446\u0435 \u043d\u0435 \u0431\u0440\u0435\u0445\u043d\u044f \u043f\u0440\u043e \u043a\u043e\u043c\u043f\u0435\u0442\u0435\u043d\u0446\u0456\u044e. \u0426\u0435 \u0440\u043e\u0437\u0440\u0438\u0432 \u043c\u0456\u0436 \u0440\u0435\u0430\u043b\u044c\u043d\u0438\u043c \u0440\u0456\u0432\u043d\u0435\u043c \u043c\u0430\u0439\u0441\u0442\u0435\u0440\u043d\u043e\u0441\u0442\u0456 \u0456 \u0434\u043e\u0437\u0432\u043e\u043b\u043e\u043c \u0441\u043e\u0431\u0456 \u0439\u043e\u0433\u043e \u0432\u0438\u0437\u043d\u0430\u0442\u0438.\n\n**\u0424\u043e\u0440\u043c\u0443\u043b\u0430:** \n\n**\u041f\u0440\u0430\u0432\u043e \u043d\u0430 \u0441\u0442\u0430\u0442\u0443\u0441 = \u041a\u043e\u043c\u043f\u0435\u0442\u0435\u043d\u0446\u0456\u044f \u2212 \u0414\u043e\u0437\u0432\u0456\u043b**\n\n\u041a\u043e\u043c\u043f\u0435\u0442\u0435\u043d\u0446\u0456\u044f \u0432\u0436\u0435 \u0454. \u0411\u0440\u0430\u043a\u0443\u0454 \u043d\u0435 \u043d\u0430\u0432\u0438\u0447\u043a\u0438, \u0430 \u0434\u043e\u0437\u0432\u043e\u043b\u0443. \u0426\u0435 \u0456 \u0454 \u0432\u0441\u044f \u0440\u043e\u0431\u043e\u0442\u0430 \u0446\u044c\u043e\u0433\u043e \u0444\u0430\u0439\u043b\u0443.\n\n**\u041f\u043e\u043c\u0438\u043b\u043a\u0430 \u0431\u0456\u043b\u044c\u0448\u043e\u0441\u0442\u0456 \u0437\u0430\u0441\u043d\u043e\u0432\u043d\u0438\u043a\u0456\u0432, \u043c\u0443\u0437\u0438\u043a\u0430\u043d\u0442\u0456\u0432, \u0442\u0432\u043e\u0440\u0446\u0456\u0432:** \u0432\u043e\u043d\u0438 \u0434\u0443\u043c\u0430\u044e\u0442\u044c, \u0449\u043e \u0442\u0440\u0438\u0432\u043e\u0433\u0430 \u0437\u043d\u0438\u043a\u043d\u0435, \u043a\u043e\u043b\u0438 \u043f\u0440\u0438\u0439\u0434\u0435 \u0449\u0435 \u043e\u0434\u0438\u043d \u0434\u043e\u043a\u0430\u0437 \u2014 \u0449\u0435 \u043e\u0434\u0438\u043d \u043a\u043b\u0456\u0454\u043d\u0442, \u0449\u0435 \u043e\u0434\u0438\u043d \u0440\u0435\u043b\u0456\u0437, \u0449\u0435 \u043e\u0434\u0438\u043d \u043a\u043e\u043d\u0442\u0440\u0430\u043a\u0442. \u041d\u0435 \u0437\u043d\u0438\u043a\u0430\u0454. \u041f\u043e\u0440\u0456\u0433 \u0434\u043e\u043a\u0430\u0437\u0456\u0432 \u0440\u0443\u0445\u0430\u0454\u0442\u044c\u0441\u044f \u0440\u0430\u0437\u043e\u043c \u0437 \u0434\u043e\u0441\u044f\u0433\u043d\u0435\u043d\u043d\u044f\u043c. \u0422\u043e\u0439, \u0445\u0442\u043e \u0447\u0435\u043a\u0430\u0454 \u043d\u0430 \"\u0434\u043e\u0441\u0442\u0430\u0442\u043d\u044c\u043e \u0434\u043e\u043a\u0430\u0437\u0456\u0432\", \u0447\u0435\u043a\u0430\u0454 \u0432\u0456\u0447\u043d\u043e. \u0422\u043e\u0439, \u0445\u0442\u043e \u0434\u0456\u0454 \u0437 \u043f\u043e\u0437\u0438\u0446\u0456\u0457 \"\u044f \u0432\u0436\u0435 \u043f\u0440\u0438\u043d\u0446\u0438\u043f\u0430\u043b\", \u0437\u0443\u043f\u0438\u043d\u044f\u0454 \u0431\u0456\u0433 \u0437\u0430 \u0434\u043e\u043a\u0430\u0437\u0430\u043c\u0438 \u2014 \u0456 \u0441\u0430\u043c\u0435 \u0442\u043e\u0434\u0456 \u0434\u043e\u043a\u0430\u0437\u0438 \u043f\u043e\u0447\u0438\u043d\u0430\u044e\u0442\u044c \u043f\u0440\u0438\u0445\u043e\u0434\u0438\u0442\u0438 \u0448\u0432\u0438\u0434\u0448\u0435.\n\n\u0426\u0435\u0439 \u0444\u0430\u0439\u043b \u2014 \u043d\u0435 \u043f\u0440\u043e \u043c\u043e\u0442\u0438\u0432\u0430\u0446\u0456\u044e. \u0426\u0435 \u043e\u043f\u0435\u0440\u0430\u0446\u0456\u0439\u043d\u0430 \u0441\u0438\u0441\u0442\u0435\u043c\u0430 \u0434\u043b\u044f \u043b\u044e\u0434\u0438\u043d\u0438, \u044f\u043a\u0430 \u0432\u0436\u0435 \u0432\u043c\u0456\u0454 \u0431\u0456\u043b\u044c\u0448\u0435, \u043d\u0456\u0436 \u0441\u043e\u0431\u0456 \u0434\u043e\u0437\u0432\u043e\u043b\u044f\u0454 \u043f\u043e\u043a\u0430\u0437\u0430\u0442\u0438. \u041c\u043e\u0434\u0443\u043b\u0456 1\u20132 \u043f\u0440\u0430\u0446\u044e\u044e\u0442\u044c \u0434\u043b\u044f \u0431\u0443\u0434\u044c-\u043a\u043e\u0433\u043e, \u0445\u0442\u043e \u0432\u0438\u0445\u043e\u0434\u0438\u0442\u044c \u0443 \u043f\u0443\u0431\u043b\u0456\u0447\u043d\u0443 \u0440\u043e\u043b\u044c. \u041c\u043e\u0434\u0443\u043b\u044c 3 \u2014 \u0434\u043b\u044f \u0431\u0443\u0434\u044c-\u043a\u043e\u0433\u043e, \u0445\u0442\u043e \u043d\u0430\u0437\u0438\u0432\u0430\u0454 \u0446\u0456\u043d\u0443 \u0441\u0432\u043e\u0457\u0439 \u043f\u0440\u0430\u0446\u0456. \u041c\u043e\u0434\u0443\u043b\u044c 4 \u2014 \u0441\u043f\u0435\u0446\u0438\u0444\u0456\u0447\u043d\u043e \u0434\u043b\u044f \u0442\u0432\u043e\u0440\u0447\u043e\u0457 \u0432\u0440\u0430\u0437\u043b\u0438\u0432\u043e\u0441\u0442\u0456 (\u043c\u0443\u0437\u0438\u043a\u0430\u043d\u0442\u0438, \u0430\u0432\u0442\u043e\u0440\u0438, \u043f\u0443\u0431\u043b\u0456\u0447\u043d\u0456 \u0433\u043e\u043b\u043e\u0441\u0438). \u041c\u043e\u0434\u0443\u043b\u044c 5 \u2014 \u0434\u043e\u0432\u0433\u0430 \u0433\u0440\u0430 \u0443\u0442\u0440\u0438\u043c\u0430\u043d\u043d\u044f \u0443\u0441\u043f\u0456\u0445\u0443 \u0431\u0435\u0437 \u0441\u0430\u0431\u043e\u0442\u0430\u0436\u0443.\n\n---\n\n## \ud83e\udde0 5 \u041c\u0410\u0419\u0421\u0422\u0420\u0406\u0412. \u0427\u041e\u041c\u0423 \u0421\u0410\u041c\u0415 \u0412\u041e\u041d\u0418.\n\n**1. Steven Pressfield \u2014 \"The War of Art\" (2002)**\n\u041d\u0430\u0437\u0432\u0430\u0432 \u0441\u0438\u043b\u0443, \u0449\u043e \u0437\u0443\u043f\u0438\u043d\u044f\u0454 \u0442\u0432\u043e\u0440\u0446\u044f \u043f\u0435\u0440\u0435\u0434 \u0432\u043b\u0430\u0441\u043d\u043e\u044e \u0432\u0435\u043b\u0438\u0447\u0447\u044e, \u2014 \u041e\u043f\u0456\u0440 (Resistance). \u041e\u043f\u0456\u0440 \u043d\u0430\u0439\u0441\u0438\u043b\u044c\u043d\u0456\u0448\u0438\u0439 \u0441\u0430\u043c\u0435 \u043f\u0435\u0440\u0435\u0434 \u043d\u0430\u0439\u0432\u0430\u0436\u043b\u0438\u0432\u0456\u0448\u043e\u044e \u0440\u043e\u0431\u043e\u0442\u043e\u044e. \u042f\u043a\u0449\u043e \u0432\u0456\u0434\u0447\u0443\u0432\u0430\u0454\u0448 \u043d\u0430\u0439\u0431\u0456\u043b\u044c\u0448\u0435 \u0432\u043d\u0443\u0442\u0440\u0456\u0448\u043d\u0454 \u0433\u0430\u043b\u044c\u043c\u043e \u2014 \u0446\u0435 \u0441\u0438\u0433\u043d\u0430\u043b, \u0449\u043e \u0440\u043e\u0431\u043e\u0442\u0430 \u0432\u0430\u0440\u0442\u0430 \u0442\u043e\u0433\u043e.\n\n**2. Dr. Valerie Young \u2014 \"The Secret Thoughts of Successful Women\" (2011)**\n\u041d\u0430\u0439\u0442\u043e\u0447\u043d\u0456\u0448\u0430 \u0442\u0438\u043f\u043e\u043b\u043e\u0433\u0456\u044f \u0441\u0430\u043c\u043e\u0437\u0432\u0430\u043d\u0441\u0442\u0432\u0430: \u041f\u0435\u0440\u0444\u0435\u043a\u0446\u0456\u043e\u043d\u0456\u0441\u0442, \u041f\u0440\u0438\u0440\u043e\u0434\u043d\u0438\u0439 \u0433\u0435\u043d\u0456\u0439, \u0421\u043e\u043b\u043e-\u0433\u0440\u0430\u0432\u0435\u0446\u044c, \u0415\u043a\u0441\u043f\u0435\u0440\u0442, \u0421\u0443\u043f\u0435\u0440\u0433\u0435\u0440\u043e\u0439. \u041f'\u044f\u0442\u044c \u0440\u0456\u0437\u043d\u0438\u0445 \u043c\u0430\u0441\u043e\u043a \u043e\u0434\u043d\u0456\u0454\u0457 \u0442\u0440\u0438\u0432\u043e\u0433\u0438. \u0422\u043e\u0447\u043d\u0430 \u0434\u0456\u0430\u0433\u043d\u043e\u0441\u0442\u0438\u043a\u0430 \u2014 \u043f\u043e\u043b\u043e\u0432\u0438\u043d\u0430 \u0440\u043e\u0431\u043e\u0442\u0438.\n\n**3. Bren\u00e9 Brown \u2014 \"Daring Greatly\" (2012)**\n\u0414\u043e\u0441\u043b\u0456\u0434\u043d\u0438\u0446\u044f \u0441\u043e\u0440\u043e\u043c\u0443 \u0439 \u0432\u0440\u0430\u0437\u043b\u0438\u0432\u043e\u0441\u0442\u0456. \u0414\u043e\u0432\u0435\u043b\u0430: \u0432\u0440\u0430\u0437\u043b\u0438\u0432\u0456\u0441\u0442\u044c, \u0432\u0438\u0441\u0442\u0430\u0432\u043b\u0435\u043d\u0430 \u0441\u0432\u0456\u0434\u043e\u043c\u043e \u0456 \u0437 \u043e\u043f\u043e\u0440\u043e\u044e, \u2014 \u043d\u0435 \u0441\u043b\u0430\u0431\u043a\u0456\u0441\u0442\u044c, \u0430 \u0454\u0434\u0438\u043d\u0438\u0439 \u0448\u043b\u044f\u0445 \u0434\u043e \u0434\u043e\u0432\u0456\u0440\u0438 \u0439 \u043b\u0456\u0434\u0435\u0440\u0441\u0442\u0432\u0430. \u0421\u043e\u0440\u043e\u043c \u0436\u0438\u0432\u0435 \u0432 \u043c\u043e\u0432\u0447\u0430\u043d\u043d\u0456; \u043d\u0430\u0437\u0432\u0430\u043d\u0435 \u0432\u0433\u043e\u043b\u043e\u0441 \u2014 \u0432\u0442\u0440\u0430\u0447\u0430\u0454 \u0432\u043b\u0430\u0434\u0443.\n\n**4. Carol Dweck \u2014 \"Mindset\" (2006)**\nFixed vs Growth mindset. \u0421\u0430\u043c\u043e\u0437\u0432\u0430\u043d\u0435\u0446\u044c \u0456\u0437 fixed mindset \u0431\u043e\u0457\u0442\u044c\u0441\u044f, \u0449\u043e \u043f\u043e\u043c\u0438\u043b\u043a\u0430 \u0432\u0438\u043a\u0440\u0438\u0454 \u0439\u043e\u0433\u043e \u044f\u043a \u0448\u0430\u0445\u0440\u0430\u044f. \u0422\u043e\u0439 \u0441\u0430\u043c\u0438\u0439 \u0444\u0430\u043a\u0442 \u0456\u0437 growth mindset \u2014 \u043f\u0440\u043e\u0441\u0442\u043e \u0434\u0430\u043d\u0456 \u0434\u043b\u044f \u043d\u0430\u0441\u0442\u0443\u043f\u043d\u043e\u0457 \u0456\u0442\u0435\u0440\u0430\u0446\u0456\u0457.\n\n**5. Ryan Holiday \u2014 \"Ego is the Enemy\" (2016)**\n\u0421\u0442\u043e\u0457\u0447\u043d\u0430 \u043b\u0456\u043d\u0437\u0430 \u043d\u0430 \u0430\u043c\u0431\u0456\u0446\u0456\u044e. \u0415\u0433\u043e \u0445\u043e\u0447\u0435 \u0432\u0438\u0437\u043d\u0430\u043d\u043d\u044f \u0434\u043e \u0440\u043e\u0431\u043e\u0442\u0438. \u041c\u0430\u0439\u0441\u0442\u0435\u0440\u043d\u0456\u0441\u0442\u044c \u0445\u043e\u0447\u0435 \u0440\u043e\u0431\u043e\u0442\u0438 \u0434\u043e \u0432\u0438\u0437\u043d\u0430\u043d\u043d\u044f. \u041d\u0430\u0439\u043d\u0435\u0431\u0435\u0437\u043f\u0435\u0447\u043d\u0456\u0448\u0438\u0439 \u043c\u043e\u043c\u0435\u043d\u0442 \u2014 \u043d\u0435 \u043f\u0440\u043e\u0432\u0430\u043b, \u0430 \u0443\u0441\u043f\u0456\u0445, \u044f\u043a\u0438\u0439 \u0435\u0433\u043e \u043f\u0440\u0438\u0432\u043b\u0430\u0441\u043d\u044e\u0454 \u0441\u043e\u0431\u0456 \u0437\u0430\u043c\u0456\u0441\u0442\u044c \u0441\u0438\u0441\u0442\u0435\u043c\u0438 \u0439 \u0434\u0438\u0441\u0446\u0438\u043f\u043b\u0456\u043d\u0438, \u0449\u043e \u0439\u043e\u0433\u043e \u0441\u0442\u0432\u043e\u0440\u0438\u043b\u0438.\n\n---\n\n## \ud83e\ude9e \u041c\u041e\u0414\u0423\u041b\u042c 1 \u2014 \u0406\u0414\u0415\u041d\u0422\u0418\u0427\u041d\u0406\u0421\u0422\u042c (\u0414\u0406\u0410\u0413\u041d\u041e\u0421\u0422\u0418\u041a\u0410)\n\n**\u041f\u0440\u0438\u043d\u0446\u0438\u043f:** \u043d\u0435 \u043c\u043e\u0436\u043d\u0430 \u0432\u0438\u043b\u0456\u043a\u0443\u0432\u0430\u0442\u0438 \u0442\u0435, \u0449\u043e \u043d\u0435 \u043d\u0430\u0437\u0432\u0430\u043d\u0435 \u0442\u043e\u0447\u043d\u043e (Young).\n\n**5 \u043c\u0430\u0441\u043e\u043a \u0441\u0430\u043c\u043e\u0437\u0432\u0430\u043d\u0441\u0442\u0432\u0430 \u2014 \u0437\u043d\u0430\u0439\u0434\u0438 \u0441\u0432\u043e\u044e:**\n\n1. **\u041f\u0435\u0440\u0444\u0435\u043a\u0446\u0456\u043e\u043d\u0456\u0441\u0442.** \"\u042f\u043a\u0449\u043e \u043d\u0435 \u0456\u0434\u0435\u0430\u043b\u044c\u043d\u043e \u2014 \u044f \u043f\u0440\u043e\u0432\u0430\u043b\u0438\u0432\u0441\u044f.\" \u0426\u0456\u043d\u0430: \u043d\u0435\u0441\u043a\u0456\u043d\u0447\u0435\u043d\u043d\u0456 \u0434\u043e\u043e\u043f\u0440\u0430\u0446\u044e\u0432\u0430\u043d\u043d\u044f \u0437\u0430\u043c\u0456\u0441\u0442\u044c \u0437\u0430\u043f\u0443\u0441\u043a\u0443.\n2. **\u041f\u0440\u0438\u0440\u043e\u0434\u043d\u0438\u0439 \u0433\u0435\u043d\u0456\u0439.** \"\u042f\u043a\u0449\u043e \u0434\u043e\u0432\u0435\u043b\u043e\u0441\u044c \u0432\u0447\u0438\u0442\u0438\u0441\u044c/\u0441\u0442\u0430\u0440\u0430\u0442\u0438\u0441\u044c \u2014 \u044f \u043d\u0435\u0441\u043f\u0440\u0430\u0432\u0436\u043d\u0456\u0439.\" \u0426\u0456\u043d\u0430: \u0443\u043d\u0438\u043a\u043d\u0435\u043d\u043d\u044f \u0432\u0441\u044c\u043e\u0433\u043e, \u0434\u0435 \u043d\u0435\u043c\u0430\u0454 \u043c\u0438\u0442\u0442\u0454\u0432\u043e\u0433\u043e \u0443\u0441\u043f\u0456\u0445\u0443.\n3. **\u0421\u043e\u043b\u043e-\u0433\u0440\u0430\u0432\u0435\u0446\u044c.** \"\u041f\u0440\u043e\u0441\u0438\u0442\u0438 \u0434\u043e\u043f\u043e\u043c\u043e\u0433\u0438 \u2014 \u0432\u0438\u0437\u043d\u0430\u0442\u0438, \u0449\u043e \u044f \u043d\u0435 \u0432\u043f\u0440\u0430\u0432\u0436\u0443 \u0441\u043e\u0431\u0456 \u0446\u0456\u043d\u0443.\" \u0426\u0456\u043d\u0430: \u043f\u0435\u0440\u0435\u0432\u0430\u043d\u0442\u0430\u0436\u0435\u043d\u043d\u044f, \u0432\u0456\u0434\u0441\u0443\u0442\u043d\u0456\u0441\u0442\u044c \u043a\u043e\u043c\u0430\u043d\u0434\u0438, \u0440\u043e\u043b\u044c enabler'\u0430 \u0437\u0430\u043c\u0456\u0441\u0442\u044c principal.\n4. **\u0415\u043a\u0441\u043f\u0435\u0440\u0442.** \"\u042f \u0449\u0435 \u043d\u0435\u0434\u043e\u0441\u0442\u0430\u0442\u043d\u044c\u043e \u0437\u043d\u0430\u044e, \u0449\u043e\u0431 \u0433\u043e\u0432\u043e\u0440\u0438\u0442\u0438 \u0437 \u043f\u043e\u0437\u0438\u0446\u0456\u0457 \u0430\u0432\u0442\u043e\u0440\u0438\u0442\u0435\u0442\u0443.\" \u0426\u0456\u043d\u0430: \u0432\u0456\u0447\u043d\u0435 \u043d\u0430\u0432\u0447\u0430\u043d\u043d\u044f \u0437\u0430\u043c\u0456\u0441\u0442\u044c \u0434\u0456\u0457, delay \u0437\u0430\u043f\u0443\u0441\u043a\u0443.\n5. **\u0421\u0443\u043f\u0435\u0440\u0433\u0435\u0440\u043e\u0439.** \"\u042f \u043c\u0443\u0448\u0443 \u043f\u0435\u0440\u0435\u0432\u0435\u0440\u0448\u0438\u0442\u0438 \u0432 \u0443\u0441\u0456\u0445 \u0440\u043e\u043b\u044f\u0445 \u043e\u0434\u0440\u0430\u0437\u0443, \u0449\u043e\u0431 \u0434\u043e\u0432\u0435\u0441\u0442\u0438 \u0441\u043e\u0431\u0456 \u043f\u0440\u0430\u0432\u043e \u0431\u0443\u0442\u0438 \u0442\u0443\u0442.\" \u0426\u0456\u043d\u0430: \u0432\u0438\u0433\u043e\u0440\u0430\u043d\u043d\u044f, \u0440\u043e\u0437\u043c\u0438\u0442\u0438\u0439 \u0444\u043e\u043a\u0443\u0441.\n\n**\u0412\u043f\u0440\u0430\u0432\u0430:** \u043d\u0430\u0437\u0432\u0438 \u0441\u0432\u043e\u044e \u043c\u0430\u0441\u043a\u0443 \u0432\u0433\u043e\u043b\u043e\u0441. \u041d\u0435 \u0430\u0431\u0441\u0442\u0440\u0430\u043a\u0442\u043d\u043e \u2014 \u043a\u043e\u043d\u043a\u0440\u0435\u0442\u043d\u0438\u0439 \u0432\u0438\u043f\u0430\u0434\u043e\u043a \u0437\u0430 \u043e\u0441\u0442\u0430\u043d\u043d\u0456\u0439 \u0442\u0438\u0436\u0434\u0435\u043d\u044c, \u0434\u0435 \u0432\u043e\u043d\u0430 \u043a\u0435\u0440\u0443\u0432\u0430\u043b\u0430 \u0440\u0456\u0448\u0435\u043d\u043d\u044f\u043c.\n\n**\u0417\u0430\u0431\u043e\u0440\u043e\u043d\u0430:**\n- \u041f\u043b\u0443\u0442\u0430\u0442\u0438 \u043c\u0430\u0441\u043a\u0443 \u0437 \u0444\u0430\u043a\u0442\u043e\u043c (\"\u044f \u043d\u0435\u0434\u043e\u0441\u0442\u0430\u0442\u043d\u044c\u043e \u0433\u043e\u0442\u043e\u0432\u0438\u0439\" \u2260 \u043f\u0440\u0430\u0432\u0434\u0430, \u0446\u0435 \u043c\u0430\u0441\u043a\u0430, \u0449\u043e \u0433\u043e\u0432\u043e\u0440\u0438\u0442\u044c)\n- \u0427\u0435\u043a\u0430\u0442\u0438 \u043d\u0430 \"\u0449\u0435 \u043e\u0434\u0438\u043d \u0434\u043e\u043a\u0430\u0437\" \u043f\u0435\u0440\u0435\u0434 \u0434\u0456\u0454\u044e\n- \u041f\u043e\u044f\u0441\u043d\u044e\u0432\u0430\u0442\u0438 \u0434\u043e\u0441\u044f\u0433\u043d\u0435\u043d\u043d\u044f \u0432\u0435\u0437\u0456\u043d\u043d\u044f\u043c, \u0442\u0430\u0439\u043c\u0456\u043d\u0433\u043e\u043c \u0447\u0438 \u0447\u0443\u0436\u043e\u044e \u0437\u0430\u0441\u043b\u0443\u0433\u043e\u044e \u0447\u0430\u0441\u0442\u0456\u0448\u0435, \u043d\u0456\u0436 \u0432\u043b\u0430\u0441\u043d\u043e\u044e \u0440\u043e\u0431\u043e\u0442\u043e\u044e\n\n---\n\n## \ud83d\udc41\ufe0f \u041c\u041e\u0414\u0423\u041b\u042c 2 \u2014 \u0412\u0418\u0414\u0418\u041c\u0406\u0421\u0422\u042c (\u041f\u0420\u0418\u0421\u0423\u0422\u041d\u0406\u0421\u0422\u042c \u0423 \u041f\u0423\u0411\u041b\u0406\u0427\u041d\u0406\u0419 \u0420\u041e\u041b\u0406)\n\n**\u041f\u0440\u0438\u043d\u0446\u0438\u043f Brown:** \u0432\u0440\u0430\u0437\u043b\u0438\u0432\u0456\u0441\u0442\u044c, \u0432\u0438\u0441\u0442\u0430\u0432\u043b\u0435\u043d\u0430 \u0437 \u043e\u043f\u043e\u0440\u043e\u044e, \u2014 \u0441\u0438\u043b\u0430. \u0412\u0440\u0430\u0437\u043b\u0438\u0432\u0456\u0441\u0442\u044c, \u0441\u0445\u043e\u0432\u0430\u043d\u0430 \u0432 \u043c\u043e\u0432\u0447\u0430\u043d\u043d\u0456, \u2014 \u0441\u043e\u0440\u043e\u043c, \u044f\u043a\u0438\u0439 \u043a\u0435\u0440\u0443\u0454 \u0442\u043e\u0431\u043e\u044e \u043d\u0435\u043f\u043e\u043c\u0456\u0442\u043d\u043e.\n\n**3 \u0440\u0456\u0432\u043d\u0456 \u0435\u043a\u0441\u043f\u043e\u0437\u0438\u0446\u0456\u0457:**\n\n- **\u041c\u043e\u0432\u0447\u0430\u0437\u043d\u0438\u0439 \u0440\u0438\u0437\u0438\u043a.** \u0422\u0438 \u0437\u043d\u0430\u0454\u0448 \u0449\u043e\u0441\u044c \u0446\u0456\u043d\u043d\u0435, \u0430\u043b\u0435 \u043d\u0435 \u043a\u0430\u0436\u0435\u0448 \u043f\u0443\u0431\u043b\u0456\u0447\u043d\u043e \u2014 \u0431\u043e \"\u0445\u0442\u043e \u044f \u0442\u0430\u043a\u0438\u0439\". \u041d\u0430\u0439\u0434\u0435\u0448\u0435\u0432\u0448\u0438\u0439 \u0441\u043f\u043e\u0441\u0456\u0431 \u0443\u043d\u0438\u043a\u043d\u0443\u0442\u0438 \u043a\u0440\u0438\u0442\u0438\u043a\u0438 \u0456 \u043d\u0430\u0439\u0434\u043e\u0440\u043e\u0436\u0447\u0438\u0439 \u0441\u043f\u043e\u0441\u0456\u0431 \u0432\u0442\u0440\u0430\u0442\u0438\u0442\u0438 \u0430\u0432\u0442\u043e\u0440\u0438\u0442\u0435\u0442.\n- **\u041a\u043e\u043d\u0442\u0440\u043e\u043b\u044c\u043e\u0432\u0430\u043d\u0430 \u0432\u0440\u0430\u0437\u043b\u0438\u0432\u0456\u0441\u0442\u044c.** \u041a\u0430\u0436\u0435\u0448 \u043f\u0440\u044f\u043c\u043e, \u0437 \u043e\u043f\u043e\u0440\u043e\u044e \u043d\u0430 \u0434\u0430\u043d\u0456 \u0439 \u0434\u043e\u0441\u0432\u0456\u0434, \u043f\u0440\u0438\u0439\u043c\u0430\u0454\u0448 \u043d\u0435\u0437\u0433\u043e\u0434\u0443 \u0431\u0435\u0437 \u0437\u0430\u0445\u0438\u0441\u0442\u0443. \u0426\u0435 \u043f\u043e\u0437\u0438\u0446\u0456\u044f principal.\n- **\u0420\u043e\u0437\u0445\u0438\u0442\u0430\u043d\u0430 \u0432\u0438\u0434\u0438\u043c\u0456\u0441\u0442\u044c.** \u041a\u0430\u0436\u0435\u0448 \u0437\u0430\u0440\u0430\u0434\u0438 \u0440\u0435\u0430\u043a\u0446\u0456\u0457, \u0448\u0443\u043a\u0430\u0454\u0448 \u043f\u0456\u0434\u0442\u0432\u0435\u0440\u0434\u0436\u0435\u043d\u043d\u044f \u0432 \u043a\u043e\u0436\u043d\u043e\u043c\u0443 \u043a\u043e\u043c\u0435\u043d\u0442\u0430\u0440\u0456. \u0426\u0435 \u043f\u043e\u0437\u0438\u0446\u0456\u044f, \u044f\u043a\u0430 \u0432\u0438\u0434\u0430\u0454 \u0442\u0440\u0438\u0432\u043e\u0433\u0443, \u043d\u0430\u0432\u0456\u0442\u044c \u044f\u043a\u0449\u043e \u043a\u043e\u043d\u0442\u0435\u043d\u0442 \u044f\u043a\u0456\u0441\u043d\u0438\u0439.\n\n**\u0422\u0440\u0435\u043d\u0443\u0432\u0430\u043d\u043d\u044f:**\n\n1. **\u041f\u0443\u0431\u043b\u0456\u043a\u0443\u0439 \u0434\u043e \u0433\u043e\u0442\u043e\u0432\u043d\u043e\u0441\u0442\u0456.** 80% \u0433\u043e\u0442\u043e\u0432\u043d\u043e\u0441\u0442\u0456 \u0439 \u0434\u0456\u044f \u2014 \u0441\u0438\u043b\u044c\u043d\u0456\u0448\u0456 \u0437\u0430 100% \u0433\u043e\u0442\u043e\u0432\u043d\u043e\u0441\u0442\u0456, \u044f\u043a\u0430 \u043d\u0456\u043a\u043e\u043b\u0438 \u043d\u0435 \u0432\u0438\u0445\u043e\u0434\u0438\u0442\u044c (Pressfield: \u041e\u043f\u0456\u0440 \u0440\u043e\u0441\u0442\u0435 \u0440\u0430\u0437\u043e\u043c \u0437 \u0432\u0456\u0434\u0442\u0435\u0440\u043c\u0456\u043d\u0443\u0432\u0430\u043d\u043d\u044f\u043c).\n2. **\u0421\u043a\u0430\u0436\u0438 \"\u044f \u043d\u0435 \u0437\u043d\u0430\u044e\" \u043e\u0434\u0438\u043d \u0440\u0430\u0437 \u043d\u0430 \u0442\u0438\u0436\u0434\u0435\u043d\u044c \u043f\u0443\u0431\u043b\u0456\u0447\u043d\u043e.** \u0426\u0435 \u043f\u0430\u0440\u0430\u0434\u043e\u043a\u0441\u0430\u043b\u044c\u043d\u043e \u043f\u0456\u0434\u0432\u0438\u0449\u0443\u0454 \u0434\u043e\u0432\u0456\u0440\u0443, \u043d\u0435 \u0437\u043d\u0438\u0436\u0443\u0454.\n3. **\u041d\u0435 \u043f\u043e\u044f\u0441\u043d\u044e\u0439 \u0441\u0432\u043e\u044e \u043f\u0440\u0438\u0441\u0443\u0442\u043d\u0456\u0441\u0442\u044c.** Principal \u043d\u0435 \u0432\u0438\u043f\u0440\u0430\u0432\u0434\u043e\u0432\u0443\u0454\u0442\u044c\u0441\u044f \u0437\u0430 \u0442\u0435, \u0449\u043e \u0432\u0456\u043d \u0443 \u043a\u0456\u043c\u043d\u0430\u0442\u0456.\n4. **Growth-\u043c\u043e\u0432\u0430 \u0437\u0430\u043c\u0456\u0441\u0442\u044c fixed-\u043c\u043e\u0432\u0438 (Dweck).** \"\u0429\u0435 \u043d\u0435 \u0432\u0438\u0439\u0448\u043b\u043e\" \u0437\u0430\u043c\u0456\u0441\u0442\u044c \"\u044f \u043d\u0435 \u0432\u043c\u0456\u044e\". \"\u0429\u043e \u0446\u0435 \u043f\u043e\u043a\u0430\u0437\u0430\u043b\u043e\" \u0437\u0430\u043c\u0456\u0441\u0442\u044c \"\u044f \u043f\u0440\u043e\u0432\u0430\u043b\u0438\u0432\u0441\u044f\".\n\n**\u0417\u0430\u0431\u043e\u0440\u043e\u043d\u0430:**\n- \u0412\u0438\u0434\u0430\u043b\u044f\u0442\u0438 \u043f\u043e\u0441\u0442 \u0447\u0435\u0440\u0435\u0437 \u043f\u0435\u0440\u0448\u0438\u0439 \u043d\u0435\u0433\u0430\u0442\u0438\u0432\u043d\u0438\u0439 \u043a\u043e\u043c\u0435\u043d\u0442\u0430\u0440\n- \u041f\u0440\u043e\u0441\u0438\u0442\u0438 \u0434\u043e\u0437\u0432\u043e\u043b\u0443 \u0433\u043e\u0432\u043e\u0440\u0438\u0442\u0438 \u0442\u0430\u043c, \u0434\u0435 \u0432\u0436\u0435 \u0454 \u043c\u0430\u043d\u0434\u0430\u0442\n- \u041f\u0440\u0438\u043c\u0435\u043d\u0448\u0443\u0432\u0430\u0442\u0438 \u0432\u043b\u0430\u0441\u043d\u0438\u0439 \u0432\u043d\u0435\u0441\u043e\u043a \u0443 \u0447\u0443\u0436\u0456\u0439 \u043f\u0440\u0438\u0441\u0443\u0442\u043d\u043e\u0441\u0442\u0456 (\"\u0442\u0430 \u0446\u0435 \u043d\u0456\u0447\u043e\u0433\u043e \u043e\u0441\u043e\u0431\u043b\u0438\u0432\u043e\u0433\u043e\")\n\n---\n\n## \ud83d\udcb0 \u041c\u041e\u0414\u0423\u041b\u042c 3 \u2014 \u0426\u0406\u041d\u0410 (\u041f\u0415\u0420\u0415\u041c\u041e\u0412\u0418\u041d\u0418 \u0417 \u0412\u041b\u0410\u0421\u041d\u041e\u042e \u0412\u0410\u0420\u0422\u0406\u0421\u0422\u042e)\n\n**\u041f\u0440\u0438\u043d\u0446\u0438\u043f:** \u0446\u0456\u043d\u0430, \u044f\u043a\u0443 \u0442\u0438 \u043d\u0430\u0437\u0438\u0432\u0430\u0454\u0448 \u0441\u043e\u0431\u0456, \u2014 \u0440\u0456\u0448\u0435\u043d\u043d\u044f \u043f\u0440\u043e \u0456\u0434\u0435\u043d\u0442\u0438\u0447\u043d\u0456\u0441\u0442\u044c, \u0430 \u043d\u0435 \u043f\u0440\u043e \u0440\u0438\u043d\u043e\u043a.\n\n**\u041a\u0430\u043b\u0456\u0431\u0440\u043e\u0432\u0430\u043d\u0456 \u0437\u0430\u043f\u0438\u0442\u0430\u043d\u043d\u044f \u0434\u043e \u0441\u0435\u0431\u0435 (\u0448\u043a\u043e\u043b\u0430 Voss, \u0437\u0430\u0441\u0442\u043e\u0441\u043e\u0432\u0430\u043d\u0430 \u0432\u0441\u0435\u0440\u0435\u0434\u0438\u043d\u0443):**\n\n> \"\u0421\u043a\u0456\u043b\u044c\u043a\u0438 \u043a\u043e\u0448\u0442\u0443\u0454 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442, \u044f\u043a\u0438\u0439 \u044f \u0434\u0430\u044e, \u0430 \u043d\u0435 \u0447\u0430\u0441, \u044f\u043a\u0438\u0439 \u044f \u0432\u0438\u0442\u0440\u0430\u0442\u0438\u0432?\"\n> \"\u0429\u043e \u0441\u0442\u0430\u043d\u0435\u0442\u044c\u0441\u044f \u0437 \u043a\u043b\u0456\u0454\u043d\u0442\u043e\u043c, \u044f\u043a\u0449\u043e \u0432\u0456\u043d \u041d\u0415 \u043e\u0442\u0440\u0438\u043c\u0430\u0454 \u0446\u0435 \u0440\u0456\u0448\u0435\u043d\u043d\u044f?\"\n> \"\u0427\u0438\u044e \u0446\u0456\u043d\u0443 \u044f \u043d\u0430\u0441\u043f\u0440\u0430\u0432\u0434\u0456 called \u2014 \u0441\u0432\u043e\u044e, \u0447\u0438 \u0446\u0456\u043d\u0443 \u0440\u043e\u043b\u0456, \u0437 \u044f\u043a\u043e\u0457 \u044f \u0437\u0432\u0438\u043a \u0441\u043b\u0443\u0436\u0438\u0442\u0438?\"\n\n**3 \u0441\u0438\u0433\u043d\u0430\u043b\u0438 leak-\u0446\u0456\u043d\u0438 (\u0432\u0442\u0440\u0430\u0442\u0438 \u0432\u0430\u0440\u0442\u043e\u0441\u0442\u0456 \u0447\u0435\u0440\u0435\u0437 \u0442\u0440\u0438\u0432\u043e\u0433\u0443, \u043d\u0435 \u0447\u0435\u0440\u0435\u0437 \u0440\u0438\u043d\u043e\u043a):**\n\n1. \u0417\u043d\u0438\u0436\u043a\u0430 \u0437'\u044f\u0432\u043b\u044f\u0454\u0442\u044c\u0441\u044f \u0434\u043e \u0442\u043e\u0433\u043e, \u044f\u043a \u0445\u0442\u043e\u0441\u044c \u043f\u043e\u043f\u0440\u043e\u0441\u0438\u0432.\n2. \u0412\u0438\u043f\u0440\u0430\u0432\u0434\u0430\u043d\u043d\u044f \u0446\u0456\u043d\u0438 \u0434\u043e\u0432\u0448\u0435, \u043d\u0456\u0436 \u043e\u043f\u0438\u0441 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442\u0443.\n3. \u041f\u043e\u043b\u0435\u0433\u0448\u0435\u043d\u043d\u044f, \u043a\u043e\u043b\u0438 \u043a\u043b\u0456\u0454\u043d\u0442 \u0442\u043e\u0440\u0433\u0443\u0454\u0442\u044c\u0441\u044f \u2014 \u0431\u043e \"\u043d\u0430\u0440\u0435\u0448\u0442\u0456 \u043d\u0435 \u0442\u0440\u0435\u0431\u0430 \u0442\u0440\u0438\u043c\u0430\u0442\u0438 \u043f\u043e\u0432\u043d\u0443 \u0446\u0438\u0444\u0440\u0443\".\n\n**\u041f\u0440\u0430\u0432\u0438\u043b\u043e:** \u043d\u0430\u0437\u0438\u0432\u0430\u0439 \u0446\u0456\u043d\u0443 principal'\u0430 \u043e\u0434\u0438\u043d \u0440\u0430\u0437, \u0431\u0435\u0437 \u043f\u043e\u043c'\u044f\u043a\u0448\u0435\u043d\u043d\u044f \u0432 \u0433\u043e\u043b\u043e\u0441\u0456, \u0431\u0435\u0437 \"\u0430\u043b\u0435 \u043c\u043e\u0436\u0435\u043c\u043e \u043e\u0431\u0433\u043e\u0432\u043e\u0440\u0438\u0442\u0438\". \u041c\u043e\u0432\u0447\u0438 \u043f\u0456\u0441\u043b\u044f \u0446\u0438\u0444\u0440\u0438. \u0425\u0442\u043e \u043f\u0435\u0440\u0448\u0438\u0439 \u0437\u0430\u043f\u043e\u0432\u043d\u044e\u0454 \u0442\u0438\u0448\u0443 \u043f\u0456\u0441\u043b\u044f \u0446\u0456\u043d\u0438 \u2014 \u0442\u043e\u0439 \u0457\u0457 \u0439 \u0437\u043d\u0438\u0436\u0443\u0454.\n\n**\u0417\u0430\u0431\u043e\u0440\u043e\u043d\u0430:**\n- \u041f\u0440\u043e\u0431\u0430\u0447\u0430\u0442\u0438\u0441\u044c \u0437\u0430 \u0446\u0456\u043d\u0443 \u0441\u043b\u043e\u0432\u0430\u043c\u0438 \u0447\u0438 \u0442\u043e\u043d\u043e\u043c\n- \u041f\u0440\u0438\u0432'\u044f\u0437\u0443\u0432\u0430\u0442\u0438 \u0446\u0456\u043d\u0443 \u0434\u043e \"\u0441\u043a\u0456\u043b\u044c\u043a\u0438 \u044f \u0433\u043e\u0442\u043e\u0432\u0438\u0439 \u043f\u043e\u043f\u0440\u043e\u0441\u0438\u0442\u0438\", \u0430 \u043d\u0435 \u0434\u043e \"\u0441\u043a\u0456\u043b\u044c\u043a\u0438 \u0446\u0435 \u043a\u043e\u0448\u0442\u0443\u0454\"\n- \u041f\u043e\u0433\u043e\u0434\u0436\u0443\u0432\u0430\u0442\u0438\u0441\u044c \u043d\u0430 \u043f\u0435\u0440\u0448\u0435 \u0437\u0430\u043f\u0435\u0440\u0435\u0447\u0435\u043d\u043d\u044f \u0431\u0435\u0437 \u043f\u0430\u0443\u0437\u0438\n\n---\n\n## \ud83c\udfa8 \u041c\u041e\u0414\u0423\u041b\u042c 4 \u2014 \u0422\u0412\u041e\u0420\u0427\u0410 \u0412\u0420\u0410\u0417\u041b\u0418\u0412\u0406\u0421\u0422\u042c (\u0414\u041b\u042f \u041f\u0423\u0411\u041b\u0406\u0427\u041d\u041e\u0413\u041e \u0413\u041e\u041b\u041e\u0421\u0423)\n\n\u0421\u043f\u0435\u0446\u0438\u0444\u0456\u0447\u043d\u043e \u0434\u043b\u044f \u0442\u0438\u0445, \u0445\u0442\u043e \u0432\u0438\u0441\u0442\u0430\u0432\u043b\u044f\u0454 \u0432\u043b\u0430\u0441\u043d\u0443 \u0442\u0432\u043e\u0440\u0447\u0456\u0441\u0442\u044c, \u0433\u043e\u043b\u043e\u0441 \u0447\u0438 \u0456\u043c'\u044f \u043d\u0430 \u0441\u0443\u0434 \u0430\u0443\u0434\u0438\u0442\u043e\u0440\u0456\u0457 \u2014 \u043c\u0443\u0437\u0438\u043a\u0430\u043d\u0442\u0438, \u0430\u0432\u0442\u043e\u0440\u0438, \u043f\u0443\u0431\u043b\u0456\u0447\u043d\u0456 \u0431\u0440\u0435\u043d\u0434\u0438.\n\n**\u041f\u0440\u0438\u043d\u0446\u0438\u043f Brown + Pressfield:** \u043c\u0438\u0441\u0442\u0435\u0446\u0442\u0432\u043e \u0431\u0435\u0437 \u0440\u0438\u0437\u0438\u043a\u0443 \u0431\u0443\u0442\u0438 \u0432\u0456\u0434\u043a\u0438\u043d\u0443\u0442\u0438\u043c \u2014 \u043d\u0435 \u043c\u0438\u0441\u0442\u0435\u0446\u0442\u0432\u043e, \u0430 \u0434\u0435\u043a\u043e\u0440\u0430\u0446\u0456\u044f. \u041e\u043f\u0456\u0440 \u043d\u0430\u0439\u0433\u0443\u0447\u043d\u0456\u0448\u0438\u0439 \u0441\u0430\u043c\u0435 \u043f\u0435\u0440\u0435\u0434 \u0440\u0435\u043b\u0456\u0437\u043e\u043c, \u044f\u043a\u0438\u0439 \u0449\u043e\u0441\u044c \u0432\u0430\u0436\u0438\u0442\u044c.\n\n**4 \u0437\u0430\u043a\u043e\u043d\u0438:**\n\n1. **\u0420\u0435\u043b\u0456\u0437 \u0434\u043e \u043a\u0440\u0438\u0442\u0438\u043a\u0438 \u2014 \u043e\u0431\u043e\u0432'\u044f\u0437\u043a\u043e\u0432\u0438\u0439 \u0440\u0438\u0442\u0443\u0430\u043b, \u043d\u0435 \u043f\u043e\u0434\u0456\u044f \u0440\u0430\u0437 \u043d\u0430 \u0436\u0438\u0442\u0442\u044f.** \u0429\u043e \u0447\u0430\u0441\u0442\u0456\u0448\u0435 \u0432\u0438\u0445\u043e\u0434\u0438\u0448 \u043d\u0430 \u0441\u0443\u0434, \u0442\u043e \u043c\u0435\u043d\u0448\u0435 \u043a\u043e\u0436\u0435\u043d \u043e\u043a\u0440\u0435\u043c\u0438\u0439 \u0432\u0438\u0445\u0456\u0434 \u0432\u0430\u0436\u0438\u0442\u044c \u0435\u043c\u043e\u0446\u0456\u0439\u043d\u043e.\n2. **\u0412\u0456\u0434\u0434\u0456\u043b\u044f\u0439 \u043a\u0440\u0438\u0442\u0438\u043a\u0443 \u0440\u043e\u0431\u043e\u0442\u0438 \u0432\u0456\u0434 \u0432\u0438\u0440\u043e\u043a\u0443 \u043e\u0441\u043e\u0431\u0438\u0441\u0442\u043e\u0441\u0442\u0456.** \"\u0426\u0435\u0439 \u0442\u0440\u0435\u043a \u043d\u0435 \u0441\u043f\u0440\u0430\u0446\u044e\u0432\u0430\u0432\" \u2260 \"\u044f \u043d\u0435 \u043c\u0443\u0437\u0438\u043a\u0430\u043d\u0442\". Fixed mindset \u0437\u043b\u0438\u0432\u0430\u0454 \u0446\u0456 \u0434\u0432\u0430 \u0440\u0435\u0447\u0435\u043d\u043d\u044f \u0432 \u043e\u0434\u043d\u0435; growth mindset \u0442\u0440\u0438\u043c\u0430\u0454 \u0457\u0445 \u043e\u043a\u0440\u0435\u043c\u043e.\n3. **\u041d\u0430\u0439\u043a\u0440\u0430\u0449\u0438\u0439 \u0442\u0432\u043e\u0440\u0447\u0438\u0439 period \u043d\u0430\u0441\u0442\u0430\u0454 \u043e\u0434\u0440\u0430\u0437\u0443 \u043f\u0456\u0441\u043b\u044f \u043d\u0430\u0439\u0431\u0456\u043b\u044c\u0448\u043e\u0433\u043e \u0441\u0442\u0440\u0430\u0445\u0443 \u043f\u043e\u043a\u0430\u0437\u0430\u0442\u0438.** \u041e\u043f\u0456\u0440 \u043c\u0430\u043a\u0441\u0438\u043c\u0430\u043b\u044c\u043d\u0438\u0439 \u043f\u0435\u0440\u0435\u0434 \u043f\u0440\u043e\u0440\u0438\u0432\u043e\u043c, \u043d\u0435 \u043f\u0435\u0440\u0435\u0434 \u043f\u043e\u0441\u0435\u0440\u0435\u0434\u043d\u0456\u0441\u0442\u044e (Pressfield).\n4. **\u0410\u0443\u0434\u0438\u0442\u043e\u0440\u0456\u044f \u0432\u0438\u0431\u0430\u0447\u0430\u0454 \u043d\u0435\u0434\u043e\u0441\u043a\u043e\u043d\u0430\u043b\u0456\u0441\u0442\u044c. \u041d\u0435 \u0432\u0438\u0431\u0430\u0447\u0430\u0454 \u0432\u0456\u0434\u0441\u0443\u0442\u043d\u0456\u0441\u0442\u044c.** \u041c\u043e\u0432\u0447\u0430\u043d\u043d\u044f \u0434\u043e\u0432\u0448\u0435 \u0448\u043a\u043e\u0434\u0438\u0442\u044c \u043a\u0430\u0440'\u0454\u0440\u0456, \u043d\u0456\u0436 \u043d\u0435\u0434\u043e\u0441\u043a\u043e\u043d\u0430\u043b\u0438\u0439 \u0440\u0435\u043b\u0456\u0437.\n\n**\u0417\u0430\u0431\u043e\u0440\u043e\u043d\u0430:**\n- \u0422\u0440\u0438\u043c\u0430\u0442\u0438 \u0433\u043e\u0442\u043e\u0432\u0443 \u0440\u043e\u0431\u043e\u0442\u0443 \u0432 \u0448\u0443\u0445\u043b\u044f\u0434\u0456 \"\u0449\u0435 \u043d\u0435 \u0447\u0430\u0441\"\n- \u0427\u0438\u0442\u0430\u0442\u0438 \u043a\u043e\u043c\u0435\u043d\u0442\u0430\u0440\u0456 \u043e\u0434\u0440\u0430\u0437\u0443 \u043f\u0456\u0441\u043b\u044f \u0440\u0435\u043b\u0456\u0437\u0443, \u0443 \u0441\u0442\u0430\u043d\u0456 \u043c\u0430\u043a\u0441\u0438\u043c\u0430\u043b\u044c\u043d\u043e\u0457 \u043d\u0435\u0437\u0430\u0445\u0438\u0449\u0435\u043d\u043e\u0441\u0442\u0456\n- \u0414\u043e\u0437\u0432\u043e\u043b\u044f\u0442\u0438 \u043e\u0434\u043d\u043e\u043c\u0443 \u043d\u0435\u0433\u0430\u0442\u0438\u0432\u043d\u043e\u043c\u0443 \u0432\u0456\u0434\u0433\u0443\u043a\u0443 \u043f\u0435\u0440\u0435\u0432\u0430\u0436\u0438\u0442\u0438 \u0434\u0435\u0441\u044f\u0442\u044c \u043d\u0435\u0439\u0442\u0440\u0430\u043b\u044c\u043d\u0438\u0445 \u0447\u0438 \u043f\u043e\u0437\u0438\u0442\u0438\u0432\u043d\u0438\u0445\n\n---\n\n## \u265f\ufe0f \u041c\u041e\u0414\u0423\u041b\u042c 5 \u2014 \u0414\u041e\u0412\u0413\u0410 \u0413\u0420\u0410 (\u0423\u0422\u0420\u0418\u041c\u0410\u041d\u041d\u042f \u0423\u0421\u041f\u0406\u0425\u0423)\n\nEgo is the Enemy (Holiday) + Dweck. \u041d\u0430\u0439\u0441\u043a\u043b\u0430\u0434\u043d\u0456\u0448\u0435 \u2014 \u043d\u0435 \u0434\u043e\u0441\u044f\u0433\u0442\u0438 \u0440\u0456\u0432\u043d\u044f principal. \u041d\u0430\u0439\u0441\u043a\u043b\u0430\u0434\u043d\u0456\u0448\u0435 \u2014 \u0437\u0430\u043b\u0438\u0448\u0438\u0442\u0438\u0441\u044c \u043d\u0438\u043c, \u043a\u043e\u043b\u0438 \u043f\u0440\u0438\u0439\u0434\u0435 \u043f\u0435\u0440\u0448\u0438\u0439 \u0440\u0435\u0430\u043b\u044c\u043d\u0438\u0439 \u0443\u0441\u043f\u0456\u0445.\n\n**5 \u0437\u0430\u043a\u043e\u043d\u0456\u0432:**\n\n1. **\u0423\u0441\u043f\u0456\u0445, \u043f\u0440\u0438\u0432\u043b\u0430\u0441\u043d\u0435\u043d\u0438\u0439 \u0435\u0433\u043e, \u0430 \u043d\u0435 \u0441\u0438\u0441\u0442\u0435\u043c\u043e\u044e \u2014 \u043a\u0440\u0438\u0445\u043a\u0438\u0439.** \u0422\u043e\u0439, \u0445\u0442\u043e \u0432\u0456\u0440\u0438\u0442\u044c \"\u0446\u0435 \u044f \u0433\u0435\u043d\u0456\u0430\u043b\u044c\u043d\u0438\u0439\", \u043b\u0430\u043c\u0430\u0454\u0442\u044c\u0441\u044f \u043d\u0430 \u043f\u0435\u0440\u0448\u0456\u0439 \u043d\u0435\u0432\u0434\u0430\u0447\u0456. \u0422\u043e\u0439, \u0445\u0442\u043e \u0437\u043d\u0430\u0454 \"\u0446\u0435 \u0434\u0438\u0441\u0446\u0438\u043f\u043b\u0456\u043d\u0430 \u0439 \u0441\u0438\u0441\u0442\u0435\u043c\u0430 \u0441\u043f\u0440\u0430\u0446\u044e\u0432\u0430\u043b\u0438\", \u043f\u043e\u0432\u0442\u043e\u0440\u044e\u0454 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442.\n2. **\u041d\u0430\u0439\u043d\u0435\u0431\u0435\u0437\u043f\u0435\u0447\u043d\u0456\u0448\u0438\u0439 \u043c\u043e\u043c\u0435\u043d\u0442 \u2014 \u043d\u0435 \u043f\u0440\u043e\u0432\u0430\u043b, \u0430 \u043f\u0435\u0440\u0448\u0435 \u0432\u0438\u0437\u043d\u0430\u043d\u043d\u044f.** \u0421\u0430\u043c\u0435 \u0442\u0443\u0442 \u0435\u0433\u043e \u0445\u043e\u0447\u0435 \u0437\u0430\u0439\u043d\u044f\u0442\u0438 \u043c\u0456\u0441\u0446\u0435 \u0440\u043e\u0431\u043e\u0442\u0438. \u0422\u0440\u0438\u043c\u0430\u0439 \u0440\u0438\u0442\u0443\u0430\u043b\u0438, \u044f\u043a\u0456 \u0442\u0435\u0431\u0435 \u0441\u044e\u0434\u0438 \u043f\u0440\u0438\u0432\u0435\u043b\u0438, \u043d\u0430\u0432\u0456\u0442\u044c \u043a\u043e\u043b\u0438 \u0437\u0434\u0430\u0454\u0442\u044c\u0441\u044f, \u0449\u043e \u0432\u043e\u043d\u0438 \u0431\u0456\u043b\u044c\u0448\u0435 \u043d\u0435 \u043f\u043e\u0442\u0440\u0456\u0431\u043d\u0456.\n3. **\u041f\u043e\u0440\u0456\u0432\u043d\u044e\u0439 \u0441\u0435\u0431\u0435 \u0456\u0437 \u0441\u043e\u0431\u043e\u044e \u043c\u0438\u043d\u0443\u043b\u043e\u0433\u043e \u0442\u0438\u0436\u043d\u044f, \u043d\u0435 \u0437 \u0447\u0443\u0436\u0438\u043c \u0444\u0456\u043d\u0456\u0448\u0435\u043c.** \u041f\u043e\u0440\u0456\u0432\u043d\u044f\u043d\u043d\u044f \u0437 \u0447\u0443\u0436\u0438\u043c \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442\u043e\u043c \u2014 \u043f\u0430\u043b\u0438\u0432\u043e \u0434\u043b\u044f \u0441\u0430\u043c\u043e\u0437\u0432\u0430\u043d\u0441\u0442\u0432\u0430, \u043d\u0435 \u0434\u043b\u044f \u0440\u043e\u0441\u0442\u0443.\n4. **\u0414\u043e\u0437\u0432\u043e\u043b\u044c \u0441\u043e\u0431\u0456 \u0431\u0443\u0442\u0438 principal-\u043e\u043c \u0443 \u0432\u043b\u0430\u0441\u043d\u0438\u0445 \u043e\u0447\u0430\u0445 \u0434\u043e \u0437\u043e\u0432\u043d\u0456\u0448\u043d\u044c\u043e\u0433\u043e \u043f\u0456\u0434\u0442\u0432\u0435\u0440\u0434\u0436\u0435\u043d\u043d\u044f, \u043d\u0435 \u043f\u0456\u0441\u043b\u044f.** \u0417\u043e\u0432\u043d\u0456\u0448\u043d\u0454 \u043f\u0456\u0434\u0442\u0432\u0435\u0440\u0434\u0436\u0435\u043d\u043d\u044f \u2014 \u043d\u0430\u0441\u043b\u0456\u0434\u043e\u043a \u0434\u043e\u0437\u0432\u043e\u043b\u0443, \u043d\u0435 \u0439\u043e\u0433\u043e \u043f\u0440\u0438\u0447\u0438\u043d\u0430.\n5. **\u0410\u0431\u0430\u043d\u0434\u043e\u043d\u0441 \u043c\u0430\u0439\u043d\u0434\u0441\u0435\u0442 \u0434\u043b\u044f \u0441\u0442\u0430\u0442\u0443\u0441\u0443 (\u043f\u0435\u0440\u0435\u043d\u0435\u0441\u0435\u043d\u043e \u0437 Magnetism OS, \u043f\u0440\u0438\u043d\u0446\u0438\u043f 6).** \u0423 \u0441\u0432\u0456\u0442\u0456 \u0431\u0430\u0433\u0430\u0442\u043e \u043c\u043e\u0436\u043b\u0438\u0432\u043e\u0441\u0442\u0435\u0439 \u0434\u043e\u0441\u044f\u0433\u0442\u0438 \u0432\u0438\u0437\u043d\u0430\u043d\u043d\u044f. \u0422\u0430 \u0446\u0456\u043d\u0430, \u044f\u043a\u0443 \u0442\u0438 \u0445\u0430\u043f\u0430\u0454\u0448 \u0447\u0435\u0440\u0435\u0437 \u0441\u0442\u0440\u0430\u0445 \u0432\u0442\u0440\u0430\u0442\u0438\u0442\u0438 \u043e\u0441\u0442\u0430\u043d\u043d\u0456\u0439 \u0448\u0430\u043d\u0441, \u2014 \u0443\u0436\u0435 \u043f\u0440\u043e\u0433\u0440\u0430\u043d\u0430. \u0426\u0456\u043d\u0430, \u044f\u043a\u0443 \u0442\u0438 \u0442\u0440\u0438\u043c\u0430\u0454\u0448 \u0437 \u043f\u043e\u0437\u0438\u0446\u0456\u0457 \u0434\u043e\u0441\u0442\u0430\u0442\u043a\u0443, \u2014 \u0437\u0430\u043b\u0438\u0448\u0438\u0442\u044c\u0441\u044f.\n\n---\n\n## \u2699\ufe0f \u041e\u041f\u0415\u0420\u0410\u0426\u0406\u0419\u041d\u0410 \u0421\u0418\u0421\u0422\u0415\u041c\u0410 \u2014 \u0429\u041e\u0414\u0415\u041d\u041d\u0410 \u041f\u0420\u0410\u041a\u0422\u0418\u041a\u0410\n\n**\u0420\u0430\u043d\u043e\u043a (10 \u0445\u0432):**\n- \u041d\u0430\u0437\u0432\u0438 \u043c\u0430\u0441\u043a\u0443 \u0442\u0438\u0436\u043d\u044f (\u041c\u043e\u0434\u0443\u043b\u044c 1) \u043e\u0434\u043d\u0438\u043c \u0440\u0435\u0447\u0435\u043d\u043d\u044f\u043c, \u043f\u0438\u0441\u044c\u043c\u043e\u0432\u043e\n- \u041e\u0434\u043d\u0430 \u0434\u0456\u044f \"80% \u0433\u043e\u0442\u043e\u0432\u043d\u043e\u0441\u0442\u0456\" \u0437\u0430\u043c\u0456\u0441\u0442\u044c \u0432\u0456\u0434\u0442\u0435\u0440\u043c\u0456\u043d\u0443\u0432\u0430\u043d\u043d\u044f \u0434\u043e 100%\n- \u0422\u0456\u043b\u043e: \u043f\u043e\u0441\u0442\u0430\u0432\u0430 principal'\u0430 \u2014 \u043d\u0430\u0432\u0456\u0442\u044c \u0443 \u043f\u043e\u0440\u043e\u0436\u043d\u0456\u0439 \u043a\u0456\u043c\u043d\u0430\u0442\u0456\n\n**\u041f\u0440\u043e\u0442\u044f\u0433\u043e\u043c \u0434\u043d\u044f \u2014 3 \u043c\u0456\u043a\u0440\u043e\u0442\u0440\u0435\u043d\u0443\u0432\u0430\u043d\u043d\u044f:**\n- 1\u00d7 \u0441\u043a\u0430\u0437\u0430\u0442\u0438 \"\u044f \u043d\u0435 \u0437\u043d\u0430\u044e\" \u0437\u0430\u043c\u0456\u0441\u0442\u044c \u0432\u0438\u0433\u0430\u0434\u0430\u043d\u043e\u0457 \u0432\u043f\u0435\u0432\u043d\u0435\u043d\u043e\u0441\u0442\u0456\n- 1\u00d7 \u043d\u0430\u0437\u0432\u0430\u0442\u0438 \u0446\u0456\u043d\u0443/\u0446\u0456\u043d\u043d\u0456\u0441\u0442\u044c \u0431\u0435\u0437 \u0432\u0438\u043f\u0440\u0430\u0432\u0434\u0430\u043d\u043d\u044f \u0439 \u0431\u0435\u0437 \u043f\u043e\u043c'\u044f\u043a\u0448\u0435\u043d\u043d\u044f \u0442\u043e\u043d\u0443\n- 1\u00d7 \u043f\u0430\u0443\u0437\u0430 \u043f\u0456\u0441\u043b\u044f \u0442\u0432\u0435\u0440\u0434\u0436\u0435\u043d\u043d\u044f, \u0437\u0430\u043c\u0456\u0441\u0442\u044c \u0437\u0430\u043f\u043e\u0432\u043d\u0435\u043d\u043d\u044f \u0442\u0438\u0448\u0456 \u043f\u043e\u044f\u0441\u043d\u0435\u043d\u043d\u044f\u043c\n\n**\u0422\u0438\u0436\u0434\u0435\u043d\u044c:**\n- 1 \u043f\u0443\u0431\u043b\u0456\u0447\u043d\u0430 \u0434\u0456\u044f \u0434\u043e \u0432\u0456\u0434\u0447\u0443\u0442\u0442\u044f \u043f\u043e\u0432\u043d\u043e\u0457 \u0433\u043e\u0442\u043e\u0432\u043d\u043e\u0441\u0442\u0456 (\u043f\u043e\u0441\u0442, \u0440\u0435\u043b\u0456\u0437, \u043f\u0440\u043e\u043f\u043e\u0437\u0438\u0446\u0456\u044f, \u0434\u0437\u0432\u0456\u043d\u043e\u043a)\n- 1 \u043f\u0435\u0440\u0435\u0433\u043b\u044f\u0434: \u0434\u0435 \u0439\u043e\u0433\u043e \u0437\u0430\u0441\u043b\u0443\u0433\u0430 \u043f\u0440\u0438\u0432\u043b\u0430\u0441\u043d\u0435\u043d\u043e \u0441\u043e\u0431\u0456, \u0434\u0435 \u2014 \u0441\u0438\u0441\u0442\u0435\u043c\u0456 \u0439 \u0434\u0438\u0441\u0446\u0438\u043f\u043b\u0456\u043d\u0456\n- 1 \u0440\u043e\u0437\u043c\u043e\u0432\u0430 \u0437 \u043b\u044e\u0434\u0438\u043d\u043e\u044e, \u044f\u043a\u0430 \u0431\u0430\u0447\u0438\u043b\u0430 \u0442\u0432\u0456\u0439 \u043f\u0430\u0442\u0435\u0440\u043d \u0437\u0437\u043e\u0432\u043d\u0456 (\u043f\u0430\u0440\u0442\u043d\u0435\u0440, \u0441\u043f\u0456\u0432\u0437\u0430\u0441\u043d\u043e\u0432\u043d\u0438\u043a, \u043d\u0430\u0441\u0442\u0430\u0432\u043d\u0438\u043a)\n\n**\u041c\u0456\u0441\u044f\u0446\u044c:**\n- \u0410\u0443\u0434\u0438\u0442 \u0446\u0456\u043d \u0456 \u043f\u0440\u043e\u043f\u043e\u0437\u0438\u0446\u0456\u0439 \u0437\u0430 30 \u0434\u043d\u0456\u0432: \u0441\u043a\u0456\u043b\u044c\u043a\u0438 \u0440\u0430\u0437\u0456\u0432 \u0437\u043d\u0438\u0436\u0435\u043d\u043e \u0446\u0456\u043d\u0443 \u0431\u0435\u0437 \u0437\u0430\u043f\u0438\u0442\u0443 \u043a\u043b\u0456\u0454\u043d\u0442\u0430?\n- \u041f\u0435\u0440\u0435\u0447\u0438\u0442\u0430\u0442\u0438 \u0446\u0435\u0439 \u0444\u0430\u0439\u043b: \u0434\u0435 \u043c\u0430\u0441\u043a\u0430 \u043a\u0435\u0440\u0443\u0432\u0430\u043b\u0430 \u0440\u0456\u0448\u0435\u043d\u043d\u044f\u043c \u043d\u0435\u043f\u043e\u043c\u0456\u0442\u043d\u043e?\n\n**\u0429\u043e \u0437\u0430\u0431\u043e\u0440\u043e\u043d\u0435\u043d\u043e \u043f\u043e\u0441\u0442\u0456\u0439\u043d\u043e:**\n- \u041f\u043e\u044f\u0441\u043d\u044e\u0432\u0430\u0442\u0438 \u0443\u0441\u043f\u0456\u0445 \u0432\u0438\u043d\u044f\u0442\u043a\u043e\u0432\u043e \u0432\u0435\u0437\u0456\u043d\u043d\u044f\u043c \u0447\u0438 \u0442\u0430\u0439\u043c\u0456\u043d\u0433\u043e\u043c\n- \u0412\u0456\u0434\u043a\u043b\u0430\u0434\u0430\u0442\u0438 \u0437\u0430\u043f\u0443\u0441\u043a/\u0440\u0435\u043b\u0456\u0437/\u0446\u0456\u043d\u0443 \u0434\u043e \"\u0449\u0435 \u043e\u0434\u043d\u043e\u0433\u043e \u0434\u043e\u043a\u0430\u0437\u0443\"\n- \u041f\u0440\u043e\u0441\u0438\u0442\u0438 \u0434\u043e\u0437\u0432\u043e\u043b\u0443 \u043d\u0430 \u0440\u043e\u043b\u044c, \u044f\u043a\u0443 \u0432\u0436\u0435 \u0437\u0430\u0439\u043c\u0430\u0454\u0448 \u0444\u0430\u043a\u0442\u0438\u0447\u043d\u043e\n\n---\n\n## \ud83e\udded \u042f\u041a \u0412\u0418\u041a\u041e\u0420\u0418\u0421\u0422\u041e\u0412\u0423\u0412\u0410\u0422\u0418 \u0426\u0415\u0419 \u0424\u0410\u0419\u041b\n\n**1. \u042f\u043a \u0448\u0430\u0440 \u043a\u043e\u0440\u043f\u0443\u0441\u0443 \u043c\u0443\u0434\u0440\u043e\u0441\u0442\u0456 MAGNETISM.** \u0426\u0435\u0439 \u0444\u0430\u0439\u043b \u2014 \u0434\u043e\u043c\u0435\u043d\u043d\u0438\u0439 \u043c\u043e\u0434\u0443\u043b\u044c \u043f\u043e\u0432\u0435\u0440\u0445 \u0441\u043f\u0456\u043b\u044c\u043d\u043e\u0433\u043e \u044f\u0434\u0440\u0430: \u0437\u0430\u0441\u0442\u043e\u0441\u043e\u0432\u0443\u0454\u0442\u044c\u0441\u044f \u0456 \u0434\u043e MATE (\u0433\u0440\u0430\u0432\u0446\u0456, \u0430\u0433\u0435\u043d\u0442\u0438 \u043f\u0456\u0434 \u0442\u0438\u0441\u043a\u043e\u043c \u0441\u0446\u0435\u043d\u0438), \u0456 \u0434\u043e MUSE (\u043c\u0443\u0437\u0438\u043a\u0430\u043d\u0442\u0438 \u043f\u0435\u0440\u0435\u0434 \u0440\u0435\u043b\u0456\u0437\u043e\u043c), \u0456 \u0434\u043e NORTH (\u0431\u0440\u0435\u043d\u0434\u0438 \u043f\u0435\u0440\u0435\u0434 \u043f\u0443\u0431\u043b\u0456\u0447\u043d\u0438\u043c \u0437\u0430\u043f\u0443\u0441\u043a\u043e\u043c). \u0422\u043e\u0439 \u0441\u0430\u043c\u0438\u0439 \u043a\u043e\u0440\u0456\u043d\u044c \u0442\u0440\u0438\u0432\u043e\u0433\u0438 \u2014 enabler \u043f\u0440\u043e\u0442\u0438 principal \u2014 \u043f\u0440\u043e\u0441\u0442\u043e \u0440\u0456\u0437\u043d\u0435 \u043f\u043e\u043b\u0435 \u043f\u0440\u043e\u044f\u0432\u0443.\n\n**2. \u042f\u043a lens \u043f\u0435\u0440\u0435\u0434 \u0435\u043a\u0441\u043f\u043e\u043d\u043e\u0432\u0430\u043d\u0438\u043c \u043c\u043e\u043c\u0435\u043d\u0442\u043e\u043c** (\u043f\u0435\u0440\u0435\u0433\u043e\u0432\u043e\u0440\u0438 \u043f\u0440\u043e \u0446\u0456\u043d\u0443, \u0440\u0435\u043b\u0456\u0437, \u043f\u0443\u0431\u043b\u0456\u0447\u043d\u0438\u0439 \u0432\u0438\u0441\u0442\u0443\u043f, \u0437\u0430\u043f\u0443\u0441\u043a):\n- \u042f\u043a\u0430 \u043c\u0430\u0441\u043a\u0430 \u0437\u0430\u0440\u0430\u0437 \u043a\u0435\u0440\u0443\u0454 \u043c\u043d\u043e\u044e?\n- \u042f \u0447\u0435\u043a\u0430\u044e \u043d\u0430 \u0434\u043e\u0437\u0432\u0456\u043b \u2014 \u0447\u0438 \u0432\u0436\u0435 \u0434\u0456\u044e \u044f\u043a principal?\n- \u0425\u0442\u043e \u0437\u0430\u043f\u043e\u0432\u043d\u044e\u0454 \u0442\u0438\u0448\u0443 \u043f\u0456\u0441\u043b\u044f \u043c\u043e\u0454\u0457 \u0446\u0438\u0444\u0440\u0438 \u0447\u0438 \u043c\u043e\u0433\u043e \u0442\u0432\u0435\u0440\u0434\u0436\u0435\u043d\u043d\u044f \u2014 \u044f, \u0447\u0438 \u0456\u043d\u0448\u0430 \u0441\u0442\u043e\u0440\u043e\u043d\u0430?\n\n**3. \u042f\u043a \u0440\u0435\u0442\u0440\u043e\u0441\u043f\u0435\u043a\u0442\u0438\u0432\u0430** (\u043f\u0456\u0441\u043b\u044f \u043f\u043e\u0434\u0456\u0457):\n- \u0414\u0435 \u044f \u043f\u0440\u0438\u0432\u043b\u0430\u0441\u043d\u0438\u0432 \u0443\u0441\u043f\u0456\u0445 \u0441\u043e\u0431\u0456, \u0434\u0435 \u2014 \u0441\u0438\u0441\u0442\u0435\u043c\u0456?\n- \u0414\u0435 \u0437\u043d\u0438\u0437\u0438\u0432 \u0446\u0456\u043d\u0443 \u0447\u0438 \u0432\u0438\u0434\u0438\u043c\u0456\u0441\u0442\u044c \u0431\u0435\u0437 \u0437\u0430\u043f\u0438\u0442\u0443?\n- \u0429\u043e \u0437\u0440\u043e\u0431\u0438\u0442\u0438 \u0456\u043d\u0430\u043a\u0448\u0435 \u0432 \u043d\u0430\u0441\u0442\u0443\u043f\u043d\u043e\u043c\u0443 \u0440\u0430\u0443\u043d\u0434\u0456?\n\n---\n\n## \ud83d\udc8e \u041e\u0414\u041d\u0410 \u0414\u0423\u041c\u041a\u0410 \u041d\u0410\u041f\u0420\u0418\u041a\u0406\u041d\u0426\u0406\n\n\u041d\u0435\u043c\u0430\u0454 \u043c\u043e\u043c\u0435\u043d\u0442\u0443, \u043a\u043e\u043b\u0438 \u0441\u0430\u043c\u043e\u0437\u0432\u0430\u043d\u0441\u0442\u0432\u043e \"\u0437\u0430\u043a\u0456\u043d\u0447\u0443\u0454\u0442\u044c\u0441\u044f \u0434\u043e\u043a\u0430\u0437\u0430\u043c\u0438\". \u0404 \u0442\u0456\u043b\u044c\u043a\u0438 \u043c\u043e\u043c\u0435\u043d\u0442, \u043a\u043e\u043b\u0438 \u0434\u043e\u0437\u0432\u0456\u043b \u0432\u0438\u0434\u0430\u0454\u0442\u044c\u0441\u044f \u0440\u0430\u043d\u0456\u0448\u0435 \u0437\u0430 \u0434\u043e\u043a\u0430\u0437 \u2014 \u0456 \u0441\u0430\u043c\u0435 \u0442\u043e\u0434\u0456 \u0434\u043e\u043a\u0430\u0437\u0438 \u0441\u0442\u0430\u044e\u0442\u044c \u0447\u0430\u0441\u0442\u0438\u043c\u0438.\n\n\u0422\u0438 \u043d\u0435 \u043c\u0443\u0441\u0438\u0448 \u0437\u0430\u0441\u043b\u0443\u0436\u0438\u0442\u0438 \u043c\u0456\u0441\u0446\u0435, \u044f\u043a\u0435 \u0444\u0430\u043a\u0442\u0438\u0447\u043d\u043e \u0432\u0436\u0435 \u0437\u0430\u0439\u043c\u0430\u0454\u0448 \u0440\u043e\u043a\u0430\u043c\u0438 \u2014 \u044f\u043a \u0442\u0440\u0435\u043d\u0435\u0440, \u044f\u043a \u0430\u0433\u0435\u043d\u0442, \u044f\u043a \u0437\u0430\u0441\u043d\u043e\u0432\u043d\u0438\u043a, \u044f\u043a \u0433\u043e\u043b\u043e\u0441, \u044f\u043a\u043e\u043c\u0443 \u0434\u043e\u0432\u0456\u0440\u044f\u044e\u0442\u044c.\n\n\u0422\u0438 \u0432\u0436\u0435 principal \u0443 \u043a\u043e\u0436\u043d\u0456\u0439 \u0440\u043e\u043b\u0456, \u0434\u0435 \u0442\u0432\u043e\u044f \u043a\u043e\u043c\u043f\u0435\u0442\u0435\u043d\u0446\u0456\u044f \u0440\u0435\u0430\u043b\u044c\u043d\u0430.\n\n**\u0417\u0430\u043b\u0438\u0448\u0438\u043b\u043e\u0441\u044c \u0442\u0456\u043b\u044c\u043a\u0438 \u043f\u0435\u0440\u0435\u0441\u0442\u0430\u0442\u0438 \u043f\u0440\u043e\u0441\u0438\u0442\u0438 \u0434\u043e\u0437\u0432\u043e\u043b\u0443 \u0432 \u0441\u0430\u043c\u043e\u0433\u043e \u0441\u0435\u0431\u0435.**\n\n---\n\n*\u2014 Principal OS v1.0*\n*\u0421\u0438\u043d\u0442\u0435\u0437: Pressfield \u00b7 Young \u00b7 Brown \u00b7 Dweck \u00b7 Holiday*\n*Domain layer for: MAGNETISM core / MATE \u00b7 MUSE \u00b7 NORTH*\n";
